{
  "name": "Hill Climber Extreme",
  "description": "A physics-based hill climbing car game using React, Matter.js, and Tailwind CSS."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
}

export interface GameScore {
  distance: number;
  bestDistance: number;
}

// Minimal Matter.js types needed for TS compilation without the full @types package
export interface Vector {
  x: number;
  y: number;
}

export interface Body {
  position: Vector;
  angle: number;
  vertices: Vector[];
  label?: string;
}

export interface Composite {
  bodies: Body[];
  constraints: any[];
  composites: Composite[];
}

export interface Engine {
  world: any;
  // Add other properties as needed
}

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;
  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.002,
    friction: 0.5,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 10 }
  });

  // Wheels
  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    collisionFilter: { group: group },
    friction: 0.9,
    density: 0.01, // Heavier wheels for stability
    restitution: 0.1, // Bounciness
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    collisionFilter: { group: group },
    friction: 0.9,
    density: 0.01,
    restitution: 0.1,
    label: 'wheelFront'
  });

  // Suspension (Constraints)
  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    stiffness: 0.2,
    damping: 0.05,
    length: 0
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    stiffness: 0.2,
    damping: 0.05,
    length: 0
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const generateTerrain = (startX: number, startY: number, length: number) => {
  const { TERRAIN_SEGMENT_WIDTH } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);
  const vertices = [];

  // Start platform
  vertices.push({ x: startX, y: startY + 500 }); // Bottom Left
  vertices.push({ x: startX, y: startY });       // Top Left

  let currentX = startX;
  let currentY = startY;

  // Generate hills
  for (let i = 0; i < segments; i++) {
    currentX += TERRAIN_SEGMENT_WIDTH;

    // Procedural generation logic
    // Mix of sine waves for rolling hills + some noise
    const noise = Math.sin(i * 0.1) * 20 + Math.sin(i * 0.03) * 60;

    // Progressively get steeper/harder
    const difficultyMultiplier = 1 + (i / segments) * 2;

    currentY = startY + noise * difficultyMultiplier;

    vertices.push({ x: currentX, y: currentY });
  }

  // End platform
  vertices.push({ x: currentX, y: currentY + 500 }); // Bottom Right
  vertices.push({ x: startX, y: startY + 500 });     // Close loop

  // Create the ground body
  // Note: Standard Matter.js bodies must be convex. For complex terrain, 
  // we usually use 'vertices' but it must be convex or decomposed.
  // For simplicity and stability in this "Basic" implementation, we will use static chain or 
  // we can treat it as one giant polygon and let Matter.js decompose it (might fail for concave).
  // Better approach for game stability: create a series of trapezoids.

  const groundParts = [];

  for (let i = 1; i < vertices.length - 2; i++) {
     const p1 = vertices[i];
     const p2 = vertices[i+1];

     // Create a quad for this segment extending downwards
     const segmentX = (p1.x + p2.x) / 2;
     const segmentY = (p1.y + p2.y) / 2 + 250; // Center of the block
     const width = Math.abs(p2.x - p1.x) + 2; // Overlap slightly to prevent cracks
     const height = 500;
     const angle = Math.atan2(p2.y - p1.y, p2.x - p1.x);

     const body = Matter.Bodies.rectangle(segmentX, segmentY, width, height, {
         isStatic: true,
         friction: 0.8,
         angle: angle,
         label: 'ground'
     });
     groundParts.push(body);
  }

  // Also keep the path data for rendering SVG separately
  return { 
      composite: Matter.Composite.create({ bodies: groundParts }), 
      pathData: vertices 
  };
};

import React from 'react';

interface MainMenuProps {
  onStart: () => void;
  bestDistance: number;
}

const MainMenu: React.FC<MainMenuProps> = ({ onStart, bestDistance }) => {
  return (
    <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm text-white">
      <div className="p-8 bg-slate-800 rounded-2xl shadow-2xl border border-slate-700 max-w-md w-full text-center">
        <h1 className="text-5xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-400 to-orange-500 mb-6 italic transform -skew-x-12">
          HILL CLIMBER
        </h1>

        <div className="mb-8 space-y-2">
          <p className="text-slate-300 text-lg">Master the terrain. Don't flip.</p>
          <div className="inline-block px-4 py-2 bg-slate-900 rounded-lg border border-slate-700">
            <span className="text-slate-400 text-sm uppercase tracking-wider">Best Distance</span>
            <div className="text-2xl font-bold text-green-400">{Math.floor(bestDistance)} m</div>
          </div>
        </div>

        <button
          onClick={onStart}
          className="w-full py-4 bg-gradient-to-r from-green-500 to-emerald-600 hover:from-green-400 hover:to-emerald-500 text-white font-bold text-xl rounded-xl shadow-lg transform transition hover:scale-105 active:scale-95"
        >
          START ENGINE
        </button>

        <div className="mt-8 grid grid-cols-2 gap-4 text-sm text-slate-400">
          <div className="bg-slate-900/50 p-3 rounded-lg">
            <kbd className="px-2 py-1 bg-slate-700 rounded text-white font-mono">→</kbd> Gas / Rotate Fwd
          </div>
          <div className="bg-slate-900/50 p-3 rounded-lg">
            <kbd className="px-2 py-1 bg-slate-700 rounded text-white font-mono">←</kbd> Brake / Rotate Back
          </div>
        </div>
      </div>
