export default MainMenu;

import React from 'react';

interface GameOverProps {
  distance: number;
  bestDistance: number;
  onRestart: () => void;
}

const GameOver: React.FC<GameOverProps> = ({ distance, bestDistance, onRestart }) => {
  const isNewRecord = distance > bestDistance;

  return (
    <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-red-900/80 backdrop-blur-md text-white">
      <div className="p-8 bg-slate-900 rounded-2xl shadow-2xl border border-red-500/50 max-w-sm w-full text-center animate-bounce-in">
        <h2 className="text-4xl font-black text-red-500 mb-2 uppercase tracking-tight">Wasted</h2>
        <p className="text-slate-400 mb-6">You flipped the car!</p>

        <div className="mb-8">
          <div className="text-sm text-slate-400 uppercase tracking-widest">Distance Reached</div>
          <div className="text-5xl font-mono font-bold text-white mb-2">
            {Math.floor(distance)}<span className="text-xl text-slate-500">m</span>
          </div>
          {isNewRecord && (
            <div className="inline-block px-3 py-1 bg-yellow-500/20 text-yellow-400 text-xs font-bold rounded-full border border-yellow-500/50 animate-pulse">
              NEW RECORD!
            </div>
          )}
        </div>

        <button
          onClick={onRestart}
          className="w-full py-3 bg-white text-slate-900 font-bold text-lg rounded-xl hover:bg-slate-200 transition shadow-xl"
        >
          TRY AGAIN
        </button>
      </div>
    </div>
  );
};

export default GameOver;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrain } from '../utils/physics';

// We need to access Matter globally or import if available. 
// Using window.Matter as per the setup in index.html
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number>();
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);

  // Refs for direct DOM manipulation (Performance optimization)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);

  // Game state refs (to avoid stale closures in loop)
  const gameStateRef = useRef({
    distance: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Terrain State for rendering
  const [terrainPath, setTerrainPath] = useState<string>('');

  // HUD State (React State is fine for 60fps UI if simple, but let's throttle or use refs if needed. 
  // For basic text, state is ok)
  const [hudDistance, setHudDistance] = useState(0);

  // Initialize Physics Engine
  useEffect(() => {
    const engine = createEngine();
    engineRef.current = engine;

    // Create World
    const car = createCar(200, 0); // Start slightly above 0
    carRef.current = car;

    const terrain = generateTerrain(0, 200, GAME_CONFIG.TERRAIN_LENGTH);

    // Generate SVG Path string for terrain
    // Move to first point
    let path = `M ${terrain.pathData[0].x} ${terrain.pathData[0].y}`;
    for(let i=1; i<terrain.pathData.length; i++) {
        path += ` L ${terrain.pathData[i].x} ${terrain.pathData[i].y}`;
    }
    path += " Z"; // Close path
    setTerrainPath(path);

    Matter.World.add(engine.world, [car, terrain.composite]);

    // Start Loop
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight') gameStateRef.current.keys.right = true;
      if (e.key === 'ArrowLeft') gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight') gameStateRef.current.keys.right = false;
      if (e.key === 'ArrowLeft') gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics Update
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Game Logic (Input -> Forces)
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    if (keys.right) {
      // Accelerate
      Matter.Body.setAngularVelocity(wheelBack, 0.3);
      Matter.Body.setAngularVelocity(wheelFront, 0.3);
      // Air control forward lean
      if(Math.abs(wheelBack.angularVelocity) > 0.4) { // Only if wheels spinning fast (in air likely)
         Matter.Body.applyForce(chassis, chassis.position, { x: 0, y: 0 }); // minimal
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.002, 0.1));
      }
    }
    if (keys.left) {
      // Brake / Reverse
      Matter.Body.setAngularVelocity(wheelBack, -0.2);
      Matter.Body.setAngularVelocity(wheelFront, -0.2);
       // Air control back lean
       if(Math.abs(wheelBack.angularVelocity) > 0.4) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.002, -0.1));
     }
    }

    // 3. Render Updates (Sync DOM with Physics)
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Update Chassis
        // We simply move the SVG group or path. 
        // Chassis is a rectangle. We can use transform.
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Update Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera Follow
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;

       // Smooth camera? For now rigid follow is fine for this game type
       const viewW = GAME_CONFIG.VIEWPORT_WIDTH;
       const viewH = GAME_CONFIG.VIEWPORT_HEIGHT;
       // Center car in view
       const viewBoxX = carX - viewW * 0.3; // Car is 30% from left
       const viewBoxY = carY - viewH * 0.6; // Car is 60% from top (so we can see hills below)

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 5. Game State Checks
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); // Simple distance calc
    gameStateRef.current.distance = currentDist;
    setHudDistance(currentDist); // Trigger react update for HUD

    // Check flipping (Angle > 90 degrees approx)
    // Normalize angle to -PI to PI
    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    // If angle is too steep (upside down), game over
    // Allow some tolerance (e.g., > 2.5 rads is basically upside down)
    if (Math.abs(angle) > 2.5) {
        // Check if chassis is touching ground (optional, but let's just fail on angle for simplicity)
         // Actually, if it's just in the air rotating it's fine. 
         // We should check collision.
         // For now, let's just say if head touches ground. 
         // Matter.js collision events are better but let's stick to simple "too much rotation" + "low speed" check?
         // No, simpler: if user holds upside down for > 60 frames?
         // Simplest: If angle > 2.5 rad (approx 140 deg), GAME OVER.
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist);
         return; // Stop loop
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div className="text-2xl font-mono font-bold">{hudDistance} m</div>
        </div>
      </div>

      <div className="absolute top-4 right-4 z-10 pointer-events-none md:hidden">
         {/* Mobile Controls Overlay Hints */}
         <div className="flex gap-2">
            <div className="w-16 h-16 rounded-full bg-white/20 border border-white/40 flex items-center justify-center">L</div>
            <div className="w-16 h-16 rounded-full bg-white/20 border border-white/40 flex items-center justify-center">R</div>
         </div>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Terrain */}
        <path 
          d={terrainPath} 
          fill={COLORS.ground} 
          stroke={COLORS.groundDark} 
          strokeWidth="5" 
        />
        {/* Detailed Terrain Pattern (Optional overlay) */}

        {/* Car Chassis */}
        {/* Centered rect drawn around 0,0, transform handles position */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        {/* Wheels */}
        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

      {/* Mobile Touch Controls - Invisible overlay */}
      <div className="absolute inset-0 flex md:hidden z-20">
         <div 
           className="w-1/2 h-full active:bg-white/5 transition-colors"
           onTouchStart={() => gameStateRef.current.keys.left = true}
           onTouchEnd={() => gameStateRef.current.keys.left = false}
         />
         <div 
           className="w-1/2 h-full active:bg-white/5 transition-colors"
           onTouchStart={() => gameStateRef.current.keys.right = true}
           onTouchEnd={() => gameStateRef.current.keys.right = false}
         />
      </div>

    </div>
  );
};

export default Game;

import React, { useState } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import { GameState } from './types';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  const startGame = () => {
    setScore(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number) => {
    setScore(distance);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu onStart={startGame} bestDistance={bestScore} />
      )}

      {gameState === GameState.PLAYING && (
        <Game onGameOver={handleGameOver} />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {/* Background for Menu/GameOver states to look nice even without the game running */}
      {gameState !== GameState.PLAYING && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-sky-500 to-sky-200">
           <div className="absolute bottom-0 w-full h-1/3 bg-emerald-600 transform skew-y-3 origin-bottom-right"></div>
           <div className="absolute bottom-0 w-full h-1/4 bg-emerald-500 transform -skew-y-2 origin-bottom-left"></div>
        </div>
      )}
    </div>
  );
};

export default App;

