  let currentY = startY;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    currentX += segmentWidth;

    // Normalized progress
    const progress = i / segments;
    const x = i * 0.12; 

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1;
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0;
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 1.5) * 0.6; 
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;
    const difficultyMultiplier = 1 + (progress * 3.0);
    const baseHeight = 60; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;
    currentY = startY - noise;

    pathPoints.push({ x: currentX, y: currentY });
  }

  // Create Physics Bodies using exact vertices (Polygons)
  // This avoids "corners sticking out" causing the car to float at peaks
  const groundParts = [];

  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];

     // Define the 4 corners of this terrain slice
     // We create a custom trapezoid/quad that perfectly fits the space
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];

     // Compute center for body placement
     const center = Matter.Vertices.centre(vertices);

     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 0.9,
         frictionStatic: 1.0,
         label: 'ground',
         render: { visible: true }
     });

     // Note: fromVertices might fail if points are not formed correctly, 
     // but our quad is convex and simple, so it works well.
     if (body) {
        groundParts.push(body);
     }
  }

  return { 
      composite: Matter.Composite.create({ bodies: groundParts }), 
      pathData: pathPoints 
  };
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrain } from '../utils/physics';

// We need to access Matter globally or import if available. 
// Using window.Matter as per the setup in index.html
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);

  // Refs for direct DOM manipulation (Performance optimization)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);

  // Game state refs (to avoid stale closures in loop)
  const gameStateRef = useRef({
    distance: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Terrain State for rendering
  const [terrainPath, setTerrainPath] = useState<string>('');

  // HUD State
  const [hudDistance, setHudDistance] = useState(0);

  // Initialize Physics Engine
  useEffect(() => {
    const engine = createEngine();
    engineRef.current = engine;

    // Create World
    const car = createCar(200, 0); // Start slightly above 0
    carRef.current = car;

    const terrain = generateTerrain(0, 200, GAME_CONFIG.TERRAIN_LENGTH);

    // Generate SVG Path string for terrain
    // We must close the loop at the bottom to fill it properly
    const points = terrain.pathData;
    if (points.length > 0) {
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        // Draw down to bottom right, then bottom left, then close
        // This matches the physics bodies depth (800)
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; // Close path
        setTerrainPath(path);
    }

    Matter.World.add(engine.world, [car, terrain.composite]);

    // Start Loop
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'd') gameStateRef.current.keys.right = true;
      if (e.key === 'ArrowLeft' || e.key === 'a') gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'd') gameStateRef.current.keys.right = false;
      if (e.key === 'ArrowLeft' || e.key === 'a') gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics Update
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Game Logic (Input -> Forces)
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const torque = GAME_CONFIG.CAR_SPEED;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    if (keys.right) {
      // Accelerate
      Matter.Body.setAngularVelocity(wheelBack, 0.4); 
      Matter.Body.setAngularVelocity(wheelFront, 0.4);

      // Air control forward lean
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    }
    if (keys.left) {
      // Brake / Reverse
      Matter.Body.setAngularVelocity(wheelBack, -0.3);
      Matter.Body.setAngularVelocity(wheelFront, -0.3);

       // Air control back lean
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render Updates (Sync DOM with Physics)
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Update Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Update Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera Follow
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;

       const viewW = GAME_CONFIG.VIEWPORT_WIDTH;
       const viewH = GAME_CONFIG.VIEWPORT_HEIGHT;
       // Center car in view
       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = carY - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 5. Game State Checks
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    setHudDistance(currentDist);

    // Check flipping
    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  const setInput = useCallback((key: 'left' | 'right', value: boolean) => {
    gameStateRef.current.keys[key] = value;
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div className="text-2xl font-mono font-bold">{hudDistance} m</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('left', true)}
           onMouseUp={() => setInput('left', false)}
           onMouseLeave={() => setInput('left', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('left', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('left', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('right', true)}
           onMouseUp={() => setInput('right', false)}
           onMouseLeave={() => setInput('right', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('right', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('right', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Terrain */}
        <path 
          d={terrainPath} 
          fill={COLORS.ground} 
          stroke={COLORS.groundDark} 
          strokeWidth="5" 
          strokeLinejoin="round"
        />

        {/* Car Chassis */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        {/* Wheels */}
        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       // Max grip to climb
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    // BOUNCINESS: Allows tires to bounce off ground
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Stiffer springs + Low damping = Bouncy, reactive suspension
  const suspensionStiffness = 0.2; // Was 0.08 (Too soft) -> 0.2 (Snappy)
  const suspensionDamping = 0.15;  // Was 0.6 (Too damped) -> 0.15 (Springy)
  const suspensionLength = 15;

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const generateTerrain = (startX: number, startY: number, length: number) => {
  const { TERRAIN_SEGMENT_WIDTH } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    currentX += segmentWidth;

    const progress = i / segments;
    const x = i * 0.15; // Increased frequency for sharper features

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1; // Flat zones
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0; // Big Hills
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    // Mix of sine waves
    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 2.5) * 0.4; // Sharper secondary bumps
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;

    // Increase height for better ramps
    const difficultyMultiplier = 1 + (progress * 3.5);
    const baseHeight = 70; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;
    currentY = startY - noise;

    pathPoints.push({ x: currentX, y: currentY });
  }

  // Create Physics Bodies
  const groundParts = [];

  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];

     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];

     const center = Matter.Vertices.centre(vertices);

     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0,  // High friction so you can accelerate up steep ramps
         frictionStatic: 1.0,
         label: 'ground',
     });

     if (body) {
        groundParts.push(body);
     }
  }

  return { 
      composite: Matter.Composite.create({ bodies: groundParts }), 
      pathData: pathPoints 
  };
};

