     }
    }

    // 3. Render Updates (Sync DOM with Physics)
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Update Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Update Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera Follow
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;

       const viewW = GAME_CONFIG.VIEWPORT_WIDTH;
       const viewH = GAME_CONFIG.VIEWPORT_HEIGHT;
       // Center car in view
       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = carY - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 5. Game State Checks
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    setHudDistance(currentDist);

    // Check flipping
    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  const setInput = useCallback((key: 'left' | 'right', value: boolean) => {
    gameStateRef.current.keys[key] = value;
  }, []);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div className="text-2xl font-mono font-bold">{hudDistance} m</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('left', true)}
           onMouseUp={() => setInput('left', false)}
           onMouseLeave={() => setInput('left', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('left', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('left', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('right', true)}
           onMouseUp={() => setInput('right', false)}
           onMouseLeave={() => setInput('right', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('right', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('right', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Terrain */}
        <path 
          d={terrainPath} 
          fill={COLORS.ground} 
          stroke={COLORS.groundDark} 
          strokeWidth="5" 
          strokeLinejoin="round"
        />

        {/* Car Chassis */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        {/* Wheels */}
        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // For variety in grass shapes
}

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.2; 
  const suspensionDamping = 0.15; 
  const suspensionLength = 15;

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const generateTerrain = (startX: number, startY: number, length: number) => {
  const { TERRAIN_SEGMENT_WIDTH } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;

    const progress = i / segments;
    const x = i * 0.15; 

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1; // Flat zones
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0; // Big Hills
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 2.5) * 0.4; 
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;
    const difficultyMultiplier = 1 + (progress * 3.5);
    const baseHeight = 70; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;
    currentY = startY - noise;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Generate Decorations (Grass) ---
    // Calculate angle of this segment
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const segmentLength = Math.hypot(currentX - prevX, currentY - prevY);

    // Add decorations randomly along this segment
    // Denser grass on flatter areas, sparser on steep slopes
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const density = 0.4 * slopeFactor; 

    if (Math.random() < density) {
        // Pick a spot along the line
        const t = Math.random();
        const decoX = prevX + (currentX - prevX) * t;
        const decoY = prevY + (currentY - prevY) * t;

        decorations.push({
            x: decoX,
            y: decoY,
            angle: angle,
            scale: 0.5 + Math.random() * 0.5,
            type: Math.floor(Math.random() * 3) // 3 variations
        });
    }
  }

  // Create Physics Bodies
  const groundParts = [];

  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];

     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];

     const center = Matter.Vertices.centre(vertices);

     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0, 
         frictionStatic: 1.0,
         label: 'ground',
     });

     if (body) {
        groundParts.push(body);
     }
  }

  return { 
      composite: Matter.Composite.create({ bodies: groundParts }), 
      pathData: pathPoints,
      decorations
  };
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrain, Decoration } from '../utils/physics';

// We need to access Matter globally or import if available. 
// Using window.Matter as per the setup in index.html
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);

  // Camera state
  const cameraZoomRef = useRef(1.0);

  // Refs for direct DOM manipulation (Performance optimization)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);

  // Game state refs (to avoid stale closures in loop)
  const gameStateRef = useRef({
    distance: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Terrain State for rendering
  const [terrainPath, setTerrainPath] = useState<string>('');
  const [decorations, setDecorations] = useState<Decoration[]>([]);

  // HUD State
  const [hudDistance, setHudDistance] = useState(0);

  // Initialize Physics Engine
  useEffect(() => {
    const engine = createEngine();
    engineRef.current = engine;

    // Create World
    const car = createCar(200, -100); 
    carRef.current = car;

    const terrain = generateTerrain(0, 200, GAME_CONFIG.TERRAIN_LENGTH);
    setDecorations(terrain.decorations);

    // Generate SVG Path string for terrain
    const points = terrain.pathData;
    if (points.length > 0) {
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        setTerrainPath(path);
    }

    Matter.World.add(engine.world, [car, terrain.composite]);

    // Start Loop
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'd') gameStateRef.current.keys.right = true;
      if (e.key === 'ArrowLeft' || e.key === 'a') gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === 'd') gameStateRef.current.keys.right = false;
      if (e.key === 'ArrowLeft' || e.key === 'a') gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics Update
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Game Logic (Input -> Forces)
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    // Smooth Acceleration Logic
    if (keys.right) {
      // Linearly ramp up angular velocity until maxSpeed
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      } else {
          // Maintain speed if already there (or let physics slow it down naturally if strictly wanted)
          Matter.Body.setAngularVelocity(wheelBack, maxSpeed);
          Matter.Body.setAngularVelocity(wheelFront, maxSpeed);
      }

      // Air control forward lean
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      // Brake / Reverse
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      // Braking is usually faster than accelerating
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }

       // Air control back lean
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    } else {
        // Idle friction (slow down gradually if no keys pressed)
        // MatterJS friction handles some, but we can help it for better feel
        // Matter.Body.setAngularVelocity(wheelBack, wheelBack.angularVelocity * 0.98);
        // Matter.Body.setAngularVelocity(wheelFront, wheelFront.angularVelocity * 0.98);
    }

    // 3. Render Updates (Sync DOM with Physics)
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Update Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Update Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera Follow & Dynamic Zoom
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;

       // Calculate car speed magnitude
       const velocity = Matter.Vector.magnitude(chassis.velocity);

       // Calculate target zoom based on speed (velocity ~0-30ish)
       // Base zoom is 1.0, max is defined in config
       // We start zooming after speed > 5
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0); // 0 to 1
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       // Smooth zoom interpolation
       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       // Center car in view
       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = carY - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 5. Game State Checks
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    setHudDistance(currentDist);

    // Check flipping
    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  const setInput = useCallback((key: 'left' | 'right', value: boolean) => {
    gameStateRef.current.keys[key] = value;
  }, []);

  // Memoize grass paths rendering
  const grassElements = useMemo(() => {
    return decorations.map((deco, i) => {
       const angleDeg = deco.angle * (180/Math.PI);
       // Simple grass tuft path
       const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
       return (
         <g key={i} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
            <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
         </g>
       );
    });
  }, [decorations]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div className="text-2xl font-mono font-bold">{hudDistance} m</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('left', true)}
           onMouseUp={() => setInput('left', false)}
           onMouseLeave={() => setInput('left', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('left', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('left', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('right', true)}
           onMouseUp={() => setInput('right', false)}
           onMouseLeave={() => setInput('right', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('right', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('right', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Terrain */}
        <g>
            <path 
            d={terrainPath} 
            fill={COLORS.ground} 
            stroke={COLORS.groundDark} 
            strokeWidth="5" 
            strokeLinejoin="round"
            />
            {/* Decorations Layer */}
            {grassElements}
        </g>

        {/* Car Chassis */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        {/* Wheels */}
        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

export class SoundManager {
    private audioContext: AudioContext | null = null;
    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    constructor() {
      // Initialize on first user interaction usually, but we prepare the constructor
      if (typeof window !== 'undefined') {
        const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
        if (AudioContextClass) {
          this.audioContext = new AudioContextClass();
        }
      }
    }

    public resume() {
      if (this.audioContext?.state === 'suspended') {
        this.audioContext.resume();
      }
    }

    public playCoinSound() {
      if (!this.audioContext) return;

      const now = Date.now();
      // Reset scale if too much time has passed (e.g., 2 seconds)
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      // C Major Scale frequencies (approximate)
      // C4, D4, E4, F4, G4, A4, B4, C5
      const scale = [261.63, 293.66, 329.63, 349.23, 392.00, 440.00, 493.88, 523.25];

      const frequency = scale[this.coinStep % scale.length];

      // Increase octave every 8 steps for fun, capped at 3 octaves
      const octaveMultiplier = Math.pow(2, Math.floor(this.coinStep / 8));
      const finalFreq = frequency * (octaveMultiplier > 4 ? 4 : octaveMultiplier);

      const osc = this.audioContext.createOscillator();
      const gain = this.audioContext.createGain();

      osc.type = 'sine'; // Sine wave for a clean "ding"
      osc.frequency.setValueAtTime(finalFreq, this.audioContext.currentTime);

      // Envelope
      gain.gain.setValueAtTime(0.1, this.audioContext.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, this.audioContext.currentTime + 0.3);

      osc.connect(gain);
      gain.connect(this.audioContext.destination);

      osc.start();
      osc.stop(this.audioContext.currentTime + 0.3);

      this.coinStep++;
    }
  }

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number;
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; // For parallax (0.1 = slow/far, 0.5 = fast/close)
  textureId: number;
}

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.2; 
  const suspensionDamping = 0.15; 
  const suspensionLength = 15;

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const generateTerrain = (startX: number, startY: number, length: number) => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;

    const progress = i / segments;
    const x = i * 0.15; 

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1; // Flat zones
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0; // Big Hills
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 2.5) * 0.4; 
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;
    const difficultyMultiplier = 1 + (progress * 3.5);
    const baseHeight = 70; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;
    currentY = startY - noise;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Generate Decorations (Grass & Coins) ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);

    // Grass
    const density = 0.4 * slopeFactor; 
    if (Math.random() < density) {
        const t = Math.random();
        const decoX = prevX + (currentX - prevX) * t;
        const decoY = prevY + (currentY - prevY) * t;

        decorations.push({
            x: decoX,
            y: decoY,
            angle: angle,
            scale: 0.5 + Math.random() * 0.5,
            type: Math.floor(Math.random() * 3) 
        });
    }

    // Coins (Chance to spawn on this segment, favor flatter areas)
    if (Math.random() < 0.1 && slopeFactor > 0.5 && i > 10) { 
        // Create 1 to 3 coins in a row
        const count = 1 + Math.floor(Math.random() * 3);
        for(let c = 0; c < count; c++) {
            const t = 0.5 + (c * 0.2) - ((count-1)*0.1); // center them
            const cx = prevX + (currentX - prevX) * t;
            const cy = prevY + (currentY - prevY) * t - 60; // 60px above ground

            // Coin Physics Body (Sensor)
            // Sensors detect collisions but don't physically react (don't bump the car)
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false } // We render via React/SVG
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Bodies
  const groundParts = [];

  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];

     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];

     const center = Matter.Vertices.centre(vertices);

     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0, 
         frictionStatic: 1.0,
         label: 'ground',
     });

     if (body) {
        groundParts.push(body);
     }
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies // Return reference to coins to track IDs
  };
};

export const generateClouds = (length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    // Generate clouds across the entire map + buffer
    const numClouds = length / 400; // One cloud every 400px approx

    for (let i = 0; i < numClouds; i++) {
        const x = (Math.random() * length) - 1000;
        const y = (Math.random() * 500) - 600; // Sky area

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, // Parallax depth
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrain, generateClouds, Decoration, Cloud } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); // Track for parallax

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Terrain & Entity State
  const [terrainPath, setTerrainPath] = useState<string>('');
  const [decorations, setDecorations] = useState<Decoration[]>([]);
  const [clouds, setClouds] = useState<Cloud[]>([]);

  // Coin State (We keep a Set of IDs that are collected to hide them)
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());
  const [activeCoins, setActiveCoins] = useState<any[]>([]); // Visual data for coins

  // HUD State
  const [hudDistance, setHudDistance] = useState(0);
  const [hudCoins, setHudCoins] = useState(0);

  // Initialize
  useEffect(() => {
    // Audio
    soundManagerRef.current = new SoundManager();

    // Physics
    const engine = createEngine();
    engineRef.current = engine;

    // World
    const car = createCar(200, -100); 
    carRef.current = car;

    const terrain = generateTerrain(0, 200, GAME_CONFIG.TERRAIN_LENGTH);
    setDecorations(terrain.decorations);

    // Store visual representation of coins from physics bodies
    setActiveCoins(terrain.coinBodies.map((b: any) => ({
        id: b.id,
        x: b.position.x,
        y: b.position.y
    })));

    // Clouds
    setClouds(generateClouds(GAME_CONFIG.TERRAIN_LENGTH));

    // Terrain Path
    const points = terrain.pathData;
    if (points.length > 0) {
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        setTerrainPath(path);
    }

    Matter.World.add(engine.world, [car, terrain.composite]);

    // Collision Event for Coins
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Check if one body is the car (any part) and the other is a coin
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                // Coin Collected!
                // 1. Remove from physics world
                Matter.World.remove(engine.world, coinBody);

                // 2. Play Sound
                soundManagerRef.current?.playCoinSound();

                // 3. Update State (using functional update to ensure fresh state)
                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;
                setHudCoins(prev => prev + GAME_CONFIG.COIN_VALUE);

                // 4. Update Visuals
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }
        }
    });

    // Start Loop
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;

      // Resume audio context on user interaction
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics Update
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Game Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    // Acceleration
    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      } else {
          Matter.Body.setAngularVelocity(wheelBack, maxSpeed);
          Matter.Body.setAngularVelocity(wheelFront, maxSpeed);
      }
      // Air lean
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render Updates
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera & Zoom
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;
       cameraPosRef.current = { x: carX, y: carY };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = carY - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);

       // Update Parallax Elements (Clouds)
       // We do this by updating a transform on a group for clouds
       const cloudGroup = document.getElementById('cloud-layer');
       if (cloudGroup) {
           // We keep the clouds static in the SVG coordinate space, but since the ViewBox moves,
           // objects "move" with the camera. To make them move *slower* (parallax),
           // we need to offset them in the direction of the camera.
           // However, simple approach: The SVG viewBox moves. 
           // If we translate the cloud layer by a fraction of the camera pos, it appears to lag behind.
           // But since individual clouds have different speeds, we render them with offsets in the loop below.
       }
    }

    // 5. Game State
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    setHudDistance(currentDist);

    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  const setInput = useCallback((key: 'left' | 'right', value: boolean) => {
    gameStateRef.current.keys[key] = value;
    if (value && soundManagerRef.current) soundManagerRef.current.resume();
  }, []);

  // Memoize rendered elements
  const grassElements = useMemo(() => {
    return decorations.map((deco, i) => {
       const angleDeg = deco.angle * (180/Math.PI);
       const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
       return (
         <g key={`grass-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
            <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
         </g>
       );
    });
  }, [decorations]);

  const coinElements = useMemo(() => {
      return activeCoins.map((coin) => {
          if (collectedCoinIds.has(coin.id)) return null;
          return (
              <g key={`coin-${coin.id}`} transform={`translate(${coin.x}, ${coin.y})`}>
                  <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                  <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                  <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                  {/* Shine effect */}
                  <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
              </g>
          )
      });
  }, [activeCoins, collectedCoinIds]);

  // Cloud Elements with Parallax (Computed in Render for smoothness or memoized with updating transforms)
  // To avoid re-rendering React component every frame for parallax, we use a trick:
  // We keep the clouds in the DOM, but since the ViewBox moves, they move. 
  // To get parallax, we need them to move *relative to the map*.
  // A simple way without heavy lifting is to make them fixed in background, but that looks 2D.
  // Better: We render them at their world position, but we don't update them every frame. 
  // Wait, if they are part of the SVG world space, they move exactly with the ground.
  // To make them move slower (parallax), we would need to update their x/y every frame based on camera.
  // Performance compromise: Render them fixed in world space but very far away (Z-index concept in 2D),
  // OR just let them drift. 
  // Let's implement simple drifting clouds + slight parallax offset based on cameraPos in a separate layer if possible.
  // Actually, for a simple game, static clouds in the sky (world space) are fine, 
  // but the user asked for "clouds that move slowly as we move".
  // To achieve true parallax in SVG without re-rendering the DOM list every frame:
  // We can group clouds by 'depth' and apply a transform to the group ref in the animate loop.

  // Ref for cloud group
  const cloudsLayerRef = useRef<SVGGElement>(null);

  // Update cloud layer parallax in animation loop
  useEffect(() => {
     // Hook into the animation loop to update cloud layer transform
     const updateClouds = () => {
         if (cloudsLayerRef.current && cameraPosRef.current) {
             // We shift the cloud layer slightly based on camera X
             // If car moves right (X increases), clouds should move right slightly (to appear further away)
             // or rather, the viewbox moves right, so clouds stay still = they move fast.
             // To make them move slow, they must follow the camera.
             const parallaxOffset = cameraPosRef.current.x * 0.5; // 50% speed of car
             cloudsLayerRef.current.setAttribute('transform', `translate(${parallaxOffset}, 0)`);
         }
         requestAnimationFrame(updateClouds);
     };
     const id = requestAnimationFrame(updateClouds);
     return () => cancelAnimationFrame(id);
  }, []);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div className="text-2xl font-mono font-bold">{hudDistance} m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div className="text-2xl font-mono font-bold">$ {hudCoins}</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('left', true)}
           onMouseUp={() => setInput('left', false)}
           onMouseLeave={() => setInput('left', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('left', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('left', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('right', true)}
           onMouseUp={() => setInput('right', false)}
           onMouseLeave={() => setInput('right', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('right', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('right', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            {/* Ground Texture Pattern */}
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                {/* Irregular dots/texture */}
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
        </defs>

        {/* Clouds Layer - Parallax Controlled */}
        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        {/* Terrain */}
        <g>
            <path 
            d={terrainPath} 
            fill="url(#groundPattern)" 
            stroke={COLORS.groundDark} 
            strokeWidth="5" 
            strokeLinejoin="round"
            />
            {/* Decorations Layer */}
            {grassElements}
            {/* Coins Layer */}
            {coinElements}
        </g>

        {/* Car Chassis */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        {/* Wheels */}
        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import React, { useState } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import { GameState } from './types';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  const startGame = () => {
    setScore(0);
    setCoins(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu onStart={startGame} bestDistance={bestScore} />
      )}

      {gameState === GameState.PLAYING && (
        <Game onGameOver={handleGameOver} />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {/* Background for Menu/GameOver states to look nice even without the game running */}
      {gameState !== GameState.PLAYING && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-sky-500 to-sky-200">
           <div className="absolute bottom-0 w-full h-1/3 bg-emerald-600 transform skew-y-3 origin-bottom-right"></div>
           <div className="absolute bottom-0 w-full h-1/4 bg-emerald-500 transform -skew-y-2 origin-bottom-left"></div>
           {/* Static clouds for menu */}
           <div className="absolute top-20 left-20 w-32 h-16 bg-white/40 rounded-full blur-xl"></div>
           <div className="absolute top-40 right-40 w-48 h-20 bg-white/30 rounded-full blur-xl"></div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number;
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; // For parallax (0.1 = slow/far, 0.5 = fast/close)
  textureId: number;
}

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // TIGHTER SUSPENSION SETTINGS
  const suspensionStiffness = 0.3; // Stiffer (was 0.2)
  const suspensionDamping = 0.2;   // More damping (was 0.15)
  const suspensionLength = 9;      // Shorter travel (was 15)

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const generateTerrain = (startX: number, startY: number, length: number) => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;

    const progress = i / segments;
    const x = i * 0.15; 

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1; // Flat zones
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0; // Big Hills
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 2.5) * 0.4; 
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;
    const difficultyMultiplier = 1 + (progress * 3.5);
    const baseHeight = 70; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;
    currentY = startY - noise;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Generate Decorations (Grass & Coins) ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);

    // Grass
    const density = 0.4 * slopeFactor; 
    if (Math.random() < density) {
        const t = Math.random();
        const decoX = prevX + (currentX - prevX) * t;
        const decoY = prevY + (currentY - prevY) * t;

        decorations.push({
            x: decoX,
            y: decoY,
            angle: angle,
            scale: 0.5 + Math.random() * 0.5,
            type: Math.floor(Math.random() * 3) 
        });
    }

    // Coins (Chance to spawn on this segment, favor flatter areas)
    if (Math.random() < 0.1 && slopeFactor > 0.5 && i > 10) { 
        // Create 1 to 3 coins in a row
        const count = 1 + Math.floor(Math.random() * 3);
        for(let c = 0; c < count; c++) {
            const t = 0.5 + (c * 0.2) - ((count-1)*0.1); // center them
            const cx = prevX + (currentX - prevX) * t;
            const cy = prevY + (currentY - prevY) * t - 60; // 60px above ground

            // Coin Physics Body (Sensor)
            // Sensors detect collisions but don't physically react (don't bump the car)
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false } // We render via React/SVG
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Bodies
  const groundParts = [];

  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];

     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];

     const center = Matter.Vertices.centre(vertices);

     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0, 
         frictionStatic: 1.0,
         label: 'ground',
     });

     if (body) {
        groundParts.push(body);
     }
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies // Return reference to coins to track IDs
  };
};

export const generateClouds = (length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    // Generate clouds across the entire map + buffer
    const numClouds = length / 400; // One cloud every 400px approx

    for (let i = 0; i < numClouds; i++) {
        const x = (Math.random() * length) - 1000;
        const y = (Math.random() * 500) - 600; // Sky area

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, // Parallax depth
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrain, generateClouds, Decoration, Cloud } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation (Performance Critical)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data (Terrain/Clouds) - computed once
  const [terrainPath, setTerrainPath] = useState<string>('');
  const [decorations, setDecorations] = useState<Decoration[]>([]);
  const [clouds, setClouds] = useState<Cloud[]>([]);

  // Coin State: We still use State for *hiding* coins because that only happens rarely (once per coin)
  // unlike the HUD which updates every frame.
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());
  const [activeCoins, setActiveCoins] = useState<any[]>([]); 

  // Initialize
  useEffect(() => {
    // Audio
    soundManagerRef.current = new SoundManager();

    // Physics
    const engine = createEngine();
    engineRef.current = engine;

    // World
    const car = createCar(200, -100); 
    carRef.current = car;

    const terrain = generateTerrain(0, 200, GAME_CONFIG.TERRAIN_LENGTH);
    setDecorations(terrain.decorations);

    // Store visual representation of coins from physics bodies
    setActiveCoins(terrain.coinBodies.map((b: any) => ({
        id: b.id,
        x: b.position.x,
        y: b.position.y
    })));

    // Clouds
    setClouds(generateClouds(GAME_CONFIG.TERRAIN_LENGTH));

    // Terrain Path
    const points = terrain.pathData;
    if (points.length > 0) {
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        setTerrainPath(path);
    }

    Matter.World.add(engine.world, [car, terrain.composite]);

    // Collision Event for Coins
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                // Coin Collected
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();

                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;

                // Direct DOM update for Coins HUD
                if (hudCoinsRef.current) {
                    hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                }

                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }
        }
    });

    // Start Loop
    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics Update
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Game Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    // Acceleration
    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      } else {
          Matter.Body.setAngularVelocity(wheelBack, maxSpeed);
          Matter.Body.setAngularVelocity(wheelFront, maxSpeed);
      }
      // Air lean
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render Updates (Direct DOM)
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Camera & Zoom
    if (svgRef.current) {
       const carX = chassis.position.x;
       const carY = chassis.position.y;
       cameraPosRef.current = { x: carX, y: carY };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = carY - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 5. Game State & HUD Updates
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;

    // Direct DOM Update for Distance HUD
    if (hudDistanceRef.current) {
        hudDistanceRef.current.innerText = `${currentDist} m`;
    }

    // Check flipping
    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver]);

  const setInput = useCallback((key: 'left' | 'right', value: boolean) => {
    gameStateRef.current.keys[key] = value;
    if (value && soundManagerRef.current) soundManagerRef.current.resume();
  }, []);

  // Memoize rendered elements to prevent re-calculations
  const grassElements = useMemo(() => {
    return decorations.map((deco, i) => {
       const angleDeg = deco.angle * (180/Math.PI);
       const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
       return (
         <g key={`grass-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
            <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
         </g>
       );
    });
  }, [decorations]);

  const coinElements = useMemo(() => {
      return activeCoins.map((coin) => {
          if (collectedCoinIds.has(coin.id)) return null;
          return (
              <g key={`coin-${coin.id}`} transform={`translate(${coin.x}, ${coin.y})`}>
                  <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                  <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                  <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                  {/* Shine effect */}
                  <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
              </g>
          )
      });
  }, [activeCoins, collectedCoinIds]);

  // Cloud Elements
  const cloudsLayerRef = useRef<SVGGElement>(null);
  useEffect(() => {
     // Separate loop for cloud parallax to decouple from physics if needed, 
     // but currently synced via requestAnimationFrame in the main loop logic implicitly via shared timeline
     const updateClouds = () => {
         if (cloudsLayerRef.current && cameraPosRef.current) {
             const parallaxOffset = cameraPosRef.current.x * 0.5; 
             cloudsLayerRef.current.setAttribute('transform', `translate(${parallaxOffset}, 0)`);
         }
         requestAnimationFrame(updateClouds);
     };
     const id = requestAnimationFrame(updateClouds);
     return () => cancelAnimationFrame(id);
  }, []);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer - Now using Refs for text updates to prevent React Re-renders */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('left', true)}
           onMouseUp={() => setInput('left', false)}
           onMouseLeave={() => setInput('left', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('left', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('left', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => setInput('right', true)}
           onMouseUp={() => setInput('right', false)}
           onMouseLeave={() => setInput('right', false)}
           onTouchStart={(e) => { e.preventDefault(); setInput('right', true); }}
           onTouchEnd={(e) => { e.preventDefault(); setInput('right', false); }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            <path 
            d={terrainPath} 
            fill="url(#groundPattern)" 
            stroke={COLORS.groundDark} 
            strokeWidth="5" 
            strokeLinejoin="round"
            />
            {grassElements}
            {coinElements}
        </g>

        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number;
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  endY: number;
  endGlobalIndex: number;
  id: number;
}

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.3; 
  const suspensionDamping = 0.2;   
  const suspensionLength = 9;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;

    // We use globalIndex for noise continuity
    const x = globalIndex * 0.15; 

    // --- Complex Terrain Algorithm ---
    const zoneOscillator = Math.sin(x * 0.2);
    let amplitudeEnvelope = 0;

    if (zoneOscillator < -0.3) {
        amplitudeEnvelope = 0.1; // Flat zones
    } else if (zoneOscillator > 0.3) {
        amplitudeEnvelope = 1.0; // Big Hills
    } else {
        const t = (zoneOscillator + 0.3) / 0.6; 
        amplitudeEnvelope = 0.1 + t * 0.9;
    }

    const primary = Math.sin(x); 
    const secondary = Math.cos(x * 2.5) * 0.4; 
    const rumble = Math.sin(x * 8) * 0.05;

    const baseShape = primary + secondary + rumble;
    // Difficulty increases slightly with global distance, but clamp it to avoid impossible walls
    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001)); 
    const baseHeight = 70; 

    const noise = baseShape * amplitudeEnvelope * difficultyMultiplier * baseHeight;

    // Smooth transition: y is relative to base, but we need absolute Y.
    // However, the noise function calculates delta Y implicitly if we just follow the curve.
    // Simpler approach for continuity: The noise function defines the *slope* or absolute height?
    // If absolute height, we might get jumps if we don't align.
    // Better approach for noise: Calculate Target Y and interpolate?
    // Let's stick to the previous diff method:
    // The previous code did: currentY = startY - noise. This implies relative to start of MAP.
    // For chunks, we must be careful.
    // Let's change to a pure derivative approach or absolute function of X.
    // Absolute function of X is safer for chunks.
    // Y(x) = - (Noise(x) * Amplitude(x))
    // We need to offset so it matches startY.

    // To ensure perfect continuity without complex math, we can just use the delta from the noise function.
    // Or simpler: The noise function `primary + secondary...` returns a value around 0.
    // Let's say `currentY` is determined by `startY + change`.

    // Let's reconstruct the absolute Y from the noise function.
    // We'll trust the previous `currentY = startY - noise` approach was actually `currentY = initialY - noise`.
    // That means `startY` passed to this function MUST be the `initialY` of the map? No.
    // If we want `generateTerrainChunk` to be stateless regarding map origin height, we need delta.

    // Revised: `currentY = prevY + slope`.
    // Slope = (Noise(x) - Noise(x-dx)). 

    // Implementation:
    // We calculate "Absolute Noise Height" at index i vs index i-1.
    const getNoiseAt = (idx: number) => {
        const nx = idx * 0.15;
        const nzOsc = Math.sin(nx * 0.2);
        let amp = 0.1;
        if (nzOsc > 0.3) amp = 1.0;
        else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

        const nPrimary = Math.sin(nx);
        const nSecondary = Math.cos(nx * 2.5) * 0.4;
        const nRumble = Math.sin(nx * 8) * 0.05;
        const diff = Math.min(2.5, 1 + (idx * 0.001));
        return (nPrimary + nSecondary + nRumble) * amp * diff * baseHeight;
    };

    const noiseCurrent = getNoiseAt(globalIndex);
    const noisePrev = getNoiseAt(globalIndex - 1);

    // The change in height
    const dy = -(noiseCurrent - noisePrev); // negative because Y down is positive in SVG/Canvas

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Decorations ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);

    // Grass
    const density = 0.4 * slopeFactor; 
    if (Math.random() < density) {
        const t = Math.random();
        const decoX = prevX + (currentX - prevX) * t;
        const decoY = prevY + (currentY - prevY) * t;

        decorations.push({
            x: decoX,
            y: decoY,
            angle: angle,
            scale: 0.5 + Math.random() * 0.5,
            type: Math.floor(Math.random() * 3) 
        });
    }

    // Coins
    if (Math.random() < 0.1 && slopeFactor > 0.5) { 
        const count = 1 + Math.floor(Math.random() * 3);
        for(let c = 0; c < count; c++) {
            const t = 0.5 + (c * 0.2) - ((count-1)*0.1); 
            const cx = prevX + (currentX - prevX) * t;
            const cy = prevY + (currentY - prevY) * t - 60; 

            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Bodies
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0, 
         frictionStatic: 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); // Keep track of physics composites to clean up if needed

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation (Performance Critical)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data (Decorations/Clouds) - now appended via chunks
  const [clouds, setClouds] = useState<Cloud[]>([]);

  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = GAME_CONFIG.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(chunkId, startX, endY, globalIndex, length);

      // Add physics
      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Add clouds for this chunk
      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      // Update ref for next time
      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      // Update state for rendering
      setChunks(prev => [...prev, newChunk]);
  }, []);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, []);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine();
    engineRef.current = engine;

    // Create World Objects
    const car = createCar(200, -100); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    // Initial Terrain (Generate 2 chunks to start)
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; // StartY = 200
    addChunk(0);
    addChunk(GAME_CONFIG.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic (Collision with Ground)
            // Check if wheels hit ground hard
            let wheelBody = null;
            let groundBody = null;

            if (bodyA.label === 'ground') groundBody = bodyA;
            if (bodyB.label === 'ground') groundBody = bodyB;

            if (bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront') wheelBody = bodyA;
            if (bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront') wheelBody = bodyB;

            if (wheelBody && groundBody) {
                // Approximate impact by speed
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    // Spawn particles
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [addChunk]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = GAME_CONFIG.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2); // Upwards arc
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 1. Physics
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Chunk Loading & Wall Update
    const carX = chassis.position.x;

    // Load new chunks if getting close to edge
    if (carX > lastChunkDataRef.current.endX - GAME_CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Update Invisible Wall (100m behind)
    const wallTargetX = carX - GAME_CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
        // Optional visual debug
        // if (wallDomRef.current) wallDomRef.current.setAttribute('x', (wallTargetX - 50).toString());
    }

    // 5. Particles Update
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                // Fade out
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                // Size
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // 6. Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 7. HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk]);

  // Render Helpers
  const grassElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        // Close shape for fill
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds]);

  // Cloud Elements
  const cloudsLayerRef = useRef<SVGGElement>(null);
  useEffect(() => {
     const updateClouds = () => {
         if (cloudsLayerRef.current && cameraPosRef.current) {
             const parallaxOffset = cameraPosRef.current.x * 0.5; 
             cloudsLayerRef.current.setAttribute('transform', `translate(${parallaxOffset}, 0)`);
         }
         requestAnimationFrame(updateClouds);
     };
     const id = requestAnimationFrame(updateClouds);
     return () => cancelAnimationFrame(id);
  }, []);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* On-screen Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World (SVG) */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {grassElements}
            {coinElements}
        </g>

        {/* Particle Pool */}
        <g>
            {Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        {/* Invisible Wall Debug (Optional) */}
        {/* <rect ref={wallDomRef} width="100" height="5000" fill="red" opacity="0.2" y="-1000" /> */}

      </svg>

    </div>
  );
};

export default Game;

import { GAME_CONFIG } from '../constants';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  endY: number;
  endGlobalIndex: number;
  id: number;
}

export const createEngine = () => {
  const engine = Matter.Engine.create();
  engine.gravity.y = GAME_CONFIG.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = GAME_CONFIG;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: 0.004, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: 'red' },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: 1.0,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.3; 
  const suspensionDamping = 0.2;   
  const suspensionLength = 9;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean // New parameter
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, LAMP_SPACING } = GAME_CONFIG;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;

  // Track lamp placement
  let lastLampX = startX;

  // Generate hill profile vertices
  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;

    // We use globalIndex for noise continuity
    const x = globalIndex * 0.15; 

    // --- Complex Terrain Algorithm ---
    const getNoiseAt = (idx: number) => {
        const nx = idx * 0.15;
        const nzOsc = Math.sin(nx * 0.2);
        let amp = 0.1;
        const baseHeight = 70;

        if (nzOsc > 0.3) amp = 1.0;
        else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

        const nPrimary = Math.sin(nx);
        const nSecondary = Math.cos(nx * 2.5) * 0.4;
        const nRumble = Math.sin(nx * 8) * 0.05;
        const diff = Math.min(2.5, 1 + (idx * 0.001));
        return (nPrimary + nSecondary + nRumble) * amp * diff * baseHeight;
    };

    const noiseCurrent = getNoiseAt(globalIndex);
    const noisePrev = getNoiseAt(globalIndex - 1);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Decorations ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);

    // Grass
    const density = 0.4 * slopeFactor; 
    if (Math.random() < density) {
        const t = Math.random();
        const decoX = prevX + (currentX - prevX) * t;
        const decoY = prevY + (currentY - prevY) * t;

        decorations.push({
            x: decoX,
            y: decoY,
            angle: angle,
            scale: 0.5 + Math.random() * 0.5,
            type: Math.floor(Math.random() * 3) // Types 0, 1, 2 are grass
        });
    }

    // Lamps (Only in Night Chunks)
    if (isNight && (currentX - lastLampX) > LAMP_SPACING) {
        // Place lamp perpendicular to ground
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3 // 3 = Lamp
        });
        lastLampX = currentX;
    }

    // Coins
    if (Math.random() < 0.1 && slopeFactor > 0.5) { 
        const count = 1 + Math.floor(Math.random() * 3);
        for(let c = 0; c < count; c++) {
            const t = 0.5 + (c * 0.2) - ((count-1)*0.1); 
            const cx = prevX + (currentX - prevX) * t;
            const cy = prevY + (currentY - prevY) * t - 60; 

            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Bodies
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: 1.0, 
         frictionStatic: 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); // Keep track of physics composites to clean up if needed

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation (Performance Critical)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data (Decorations/Clouds) - now appended via chunks
  const [clouds, setClouds] = useState<Cloud[]>([]);

  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = GAME_CONFIG.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(chunkId, startX, endY, globalIndex, length, isNightRef.current);

      // Add physics
      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Add clouds for this chunk
      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      // Update ref for next time
      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      // Update state for rendering
      setChunks(prev => [...prev, newChunk]);
  }, []);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, []);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine();
    engineRef.current = engine;

    // Create World Objects
    const car = createCar(200, -100); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    // Initial Terrain (Generate 2 chunks to start)
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; // StartY = 200
    addChunk(0);
    addChunk(GAME_CONFIG.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic (Collision with Ground)
            // Check if wheels hit ground hard
            let wheelBody = null;
            let groundBody = null;

            if (bodyA.label === 'ground') groundBody = bodyA;
            if (bodyB.label === 'ground') groundBody = bodyB;

            if (bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront') wheelBody = bodyA;
            if (bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront') wheelBody = bodyB;

            if (wheelBody && groundBody) {
                // Approximate impact by speed
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    // Spawn particles
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [addChunk]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = GAME_CONFIG.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2); // Upwards arc
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  // Helper for color interpolation
  const interpolateColor = (color1: string, color2: string, factor: number) => {
    // Basic hex interpolation helper
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 0. Day/Night Cycle
    gameTimeRef.current = (gameTimeRef.current + 1) % GAME_CONFIG.DAY_CYCLE_FRAMES;
    const cyclePos = gameTimeRef.current / GAME_CONFIG.DAY_CYCLE_FRAMES; // 0 to 1

    // Day = 0-0.4, Sunset = 0.4-0.5, Night = 0.5-0.9, Sunrise = 0.9-1.0
    let skyTop = COLORS.skyStart;
    let skyBot = COLORS.skyEnd;

    if (cyclePos > 0.4 && cyclePos <= 0.5) {
        // Sunset
        const t = (cyclePos - 0.4) * 10; // 0 to 1
        skyTop = interpolateColor(COLORS.skyStart, COLORS.skyNightStart, t);
        skyBot = interpolateColor(COLORS.skyEnd, COLORS.skyNightEnd, t);
    } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
        // Night
        skyTop = COLORS.skyNightStart;
        skyBot = COLORS.skyNightEnd;
    } else if (cyclePos > 0.9) {
        // Sunrise
        const t = (cyclePos - 0.9) * 10;
        skyTop = interpolateColor(COLORS.skyNightStart, COLORS.skyStart, t);
        skyBot = interpolateColor(COLORS.skyNightEnd, COLORS.skyEnd, t);
    }

    // Set Night Flag for new chunks
    isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

    // Apply background
    if (containerRef.current) {
        containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
    }

    // 1. Physics
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Chunk Loading & Wall Update
    const carX = chassis.position.x;

    // Load new chunks if getting close to edge
    if (carX > lastChunkDataRef.current.endX - GAME_CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Update Invisible Wall (100m behind)
    const wallTargetX = carX - GAME_CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // 5. Particles Update
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                // Fade out
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                // Size
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // 6. Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 7. HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk]);

  // Render Helpers
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90})`}>
                  {/* Post */}
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  {/* Head */}
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  {/* Light Source */}
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  {/* Glow */}
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           // Grass
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        {/* Particles */}
        <g>
            {Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); // Keep track of physics composites to clean up if needed

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation (Performance Critical)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data (Decorations/Clouds) - now appended via chunks
  const [clouds, setClouds] = useState<Cloud[]>([]);

  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = GAME_CONFIG.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(chunkId, startX, endY, globalIndex, length, isNightRef.current);

      // Add physics
      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Add clouds for this chunk
      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      // Update ref for next time
      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      // Update state for rendering
      setChunks(prev => [...prev, newChunk]);
  }, []);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, []);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine();
    engineRef.current = engine;

    // Create World Objects
    const car = createCar(200, -100); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    // Initial Terrain (Generate 2 chunks to start)
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; // StartY = 200
    addChunk(0);
    addChunk(GAME_CONFIG.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic (Collision with Ground)
            // Check if wheels hit ground hard
            let wheelBody = null;
            let groundBody = null;

            if (bodyA.label === 'ground') groundBody = bodyA;
            if (bodyB.label === 'ground') groundBody = bodyB;

            if (bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront') wheelBody = bodyA;
            if (bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront') wheelBody = bodyB;

            if (wheelBody && groundBody) {
                // Approximate impact by speed
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    // Spawn particles
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [addChunk]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = GAME_CONFIG.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2); // Upwards arc
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  // Helper for color interpolation
  const interpolateColor = (color1: string, color2: string, factor: number) => {
    // Basic hex interpolation helper
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 0. Day/Night Cycle
    gameTimeRef.current = (gameTimeRef.current + 1) % GAME_CONFIG.DAY_CYCLE_FRAMES;
    const cyclePos = gameTimeRef.current / GAME_CONFIG.DAY_CYCLE_FRAMES; // 0 to 1

    // Day = 0-0.4, Sunset = 0.4-0.5, Night = 0.5-0.9, Sunrise = 0.9-1.0
    let skyTop = COLORS.skyStart;
    let skyBot = COLORS.skyEnd;

    if (cyclePos > 0.4 && cyclePos <= 0.5) {
        // Sunset
        const t = (cyclePos - 0.4) * 10; // 0 to 1
        skyTop = interpolateColor(COLORS.skyStart, COLORS.skyNightStart, t);
        skyBot = interpolateColor(COLORS.skyEnd, COLORS.skyNightEnd, t);
    } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
        // Night
        skyTop = COLORS.skyNightStart;
        skyBot = COLORS.skyNightEnd;
    } else if (cyclePos > 0.9) {
        // Sunrise
        const t = (cyclePos - 0.9) * 10;
        skyTop = interpolateColor(COLORS.skyNightStart, COLORS.skyStart, t);
        skyBot = interpolateColor(COLORS.skyNightEnd, COLORS.skyEnd, t);
    }

    // Set Night Flag for new chunks
    isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

    // Apply background
    if (containerRef.current) {
        containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
    }

    // 1. Physics
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Chunk Loading & Wall Update
    const carX = chassis.position.x;

    // Load new chunks if getting close to edge
    if (carX > lastChunkDataRef.current.endX - GAME_CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Update Invisible Wall (100m behind)
    const wallTargetX = carX - GAME_CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // 5. Particles Update
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                // Fade out
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                // Size
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // 6. Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 7. HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk]);

  // Render Helpers
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90})`}>
                  {/* Post */}
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  {/* Head */}
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  {/* Light Source */}
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  {/* Glow */}
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           // Grass
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-red-500/20 active:bg-red-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-emerald-500/20 active:bg-emerald-500/50 backdrop-blur-sm shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        {/* Particles */}
        <g>
            {Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { GAME_CONFIG, COLORS } from '../constants';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

const Game: React.FC<GameProps> = ({ onGameOver }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); // Keep track of physics composites to clean up if needed

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation (Performance Critical)
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data (Decorations/Clouds) - now appended via chunks
  const [clouds, setClouds] = useState<Cloud[]>([]);

  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = GAME_CONFIG.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(chunkId, startX, endY, globalIndex, length, isNightRef.current);

      // Add physics
      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Add clouds for this chunk
      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      // Update ref for next time
      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      // Update state for rendering
      setChunks(prev => [...prev, newChunk]);
  }, []);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, []);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine();
    engineRef.current = engine;

    // Create World Objects
    const car = createCar(200, -100); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    // Initial Terrain (Generate 2 chunks to start)
    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; // StartY = 200
    addChunk(0);
    addChunk(GAME_CONFIG.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += GAME_CONFIG.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic (Collision with Ground)
            // Check if wheels hit ground hard
            let wheelBody = null;
            let groundBody = null;

            if (bodyA.label === 'ground') groundBody = bodyA;
            if (bodyB.label === 'ground') groundBody = bodyB;

            if (bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront') wheelBody = bodyA;
            if (bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront') wheelBody = bodyB;

            if (wheelBody && groundBody) {
                // Approximate impact by speed
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    // Spawn particles
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [addChunk]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = GAME_CONFIG.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2); // Upwards arc
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  // Helper for color interpolation
  const interpolateColor = (color1: string, color2: string, factor: number) => {
    // Basic hex interpolation helper
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  // Game Loop
  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // 0. Day/Night Cycle
    gameTimeRef.current = (gameTimeRef.current + 1) % GAME_CONFIG.DAY_CYCLE_FRAMES;
    const cyclePos = gameTimeRef.current / GAME_CONFIG.DAY_CYCLE_FRAMES; // 0 to 1

    // Day = 0-0.4, Sunset = 0.4-0.5, Night = 0.5-0.9, Sunrise = 0.9-1.0
    let skyTop = COLORS.skyStart;
    let skyBot = COLORS.skyEnd;

    if (cyclePos > 0.4 && cyclePos <= 0.5) {
        // Sunset
        const t = (cyclePos - 0.4) * 10; // 0 to 1
        skyTop = interpolateColor(COLORS.skyStart, COLORS.skyNightStart, t);
        skyBot = interpolateColor(COLORS.skyEnd, COLORS.skyNightEnd, t);
    } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
        // Night
        skyTop = COLORS.skyNightStart;
        skyBot = COLORS.skyNightEnd;
    } else if (cyclePos > 0.9) {
        // Sunrise
        const t = (cyclePos - 0.9) * 10;
        skyTop = interpolateColor(COLORS.skyNightStart, COLORS.skyStart, t);
        skyBot = interpolateColor(COLORS.skyNightEnd, COLORS.skyEnd, t);
    }

    // Set Night Flag for new chunks
    isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

    // Apply background
    if (containerRef.current) {
        containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
    }

    // 1. Physics
    Matter.Engine.update(engine, 1000 / 60);

    // 2. Logic
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = GAME_CONFIG.CAR_SPEED;
    const acceleration = GAME_CONFIG.ACCELERATION;
    const airRotation = GAME_CONFIG.AIR_ROTATION_SPEED;

    if (keys.right) {
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          const newSpeed = Math.min(currentSpeed + acceleration, maxSpeed);
          Matter.Body.setAngularVelocity(wheelBack, newSpeed);
          Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
      if(Math.abs(wheelBack.angularVelocity) > 0.5) { 
         Matter.Body.setAngularVelocity(chassis, Math.min(chassis.angularVelocity + 0.005, airRotation));
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         const newSpeed = Math.max(currentSpeed - acceleration * 1.5, targetReverse);
         Matter.Body.setAngularVelocity(wheelBack, newSpeed);
         Matter.Body.setAngularVelocity(wheelFront, newSpeed);
      }
       if(Math.abs(wheelBack.angularVelocity) > 0.5) {
        Matter.Body.setAngularVelocity(chassis, Math.max(chassis.angularVelocity - 0.005, -airRotation));
     }
    }

    // 3. Render
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        // Chassis
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheels
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // 4. Chunk Loading & Wall Update
    const carX = chassis.position.x;

    // Load new chunks if getting close to edge
    if (carX > lastChunkDataRef.current.endX - GAME_CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Update Invisible Wall (100m behind)
    const wallTargetX = carX - GAME_CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // 5. Particles Update
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                // Fade out
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                // Size
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // 6. Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (GAME_CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = GAME_CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = GAME_CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // 7. HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    let angle = chassis.angle % (Math.PI * 2);
    if (angle > Math.PI) angle -= Math.PI * 2;
    if (angle < -Math.PI) angle += Math.PI * 2;

    if (Math.abs(angle) > 2.8) { 
         gameStateRef.current.isGameOver = true;
         onGameOver(currentDist, gameStateRef.current.coins);
         return; 
    }

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk]);

  // Render Helpers
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             // FIX: Removed the +90 rotation so the lamp stands perpendicular to the ground
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  {/* Post */}
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  {/* Head */}
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  {/* Light Source */}
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  {/* Glow */}
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           // Grass
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={GAME_CONFIG.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={GAME_CONFIG.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Controls - Optimized: Removed backdrop-blur-sm, simplified background */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-black/60 active:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-black/60 active:bg-emerald-900/60 shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        {/* Particles */}
        <g>
            {Array.from({ length: GAME_CONFIG.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
            fill={COLORS.carBody}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={GAME_CONFIG.WHEEL_SIZE} fill={COLORS.carWheel} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-GAME_CONFIG.WHEEL_SIZE} y1="0" x2={GAME_CONFIG.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE} x2="0" y2={GAME_CONFIG.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

