          <div className="bg-slate-900/50 p-3 rounded-lg">
            <kbd className="px-2 py-1 bg-slate-700 rounded text-white font-mono">→</kbd> Gas / Rotate Fwd
          </div>
          <div className="bg-slate-900/50 p-3 rounded-lg">
            <kbd className="px-2 py-1 bg-slate-700 rounded text-white font-mono">←</kbd> Brake / Rotate Back
          </div>
        </div>
      </div>
    </div>
  );
};

