            return (
              <div 
                key={car.id}
                onClick={() => onSelect(car)}
                className={`
                  relative p-4 rounded-xl border-2 cursor-pointer transition-all transform hover:scale-[1.02]
                  ${isSelected ? 'border-yellow-400 bg-slate-800 shadow-[0_0_20px_rgba(250,204,21,0.2)]' : 'border-slate-700 bg-slate-800/50 hover:border-slate-500'}
                `}
              >
