import React, { useState } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import CarSelection from './components/CarSelection';
import { GameState, CarModel } from './types';
import { CAR_MODELS } from './constants';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  // Car Selection State
  const [selectedCar, setSelectedCar] = useState<CarModel>(CAR_MODELS[0]);
  const [isGarageOpen, setIsGarageOpen] = useState(false);

  const startGame = () => {
    setScore(0);
    setCoins(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  const handleCarSelect = (car: CarModel) => {
    setSelectedCar(car);
  };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu 
          onStart={startGame} 
          onOpenGarage={() => setIsGarageOpen(true)}
          bestDistance={bestScore} 
        />
      )}

      {gameState === GameState.PLAYING && (
        <Game onGameOver={handleGameOver} selectedCar={selectedCar} />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {isGarageOpen && (
        <CarSelection 
          currentCarId={selectedCar.id} 
          onSelect={handleCarSelect} 
          onClose={() => setIsGarageOpen(false)} 
        />
      )}

      {/* Background for Menu/GameOver states to look nice even without the game running */}
      {gameState !== GameState.PLAYING && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-sky-500 to-sky-200">
           <div className="absolute bottom-0 w-full h-1/3 bg-emerald-600 transform skew-y-3 origin-bottom-right"></div>
           <div className="absolute bottom-0 w-full h-1/4 bg-emerald-500 transform -skew-y-2 origin-bottom-left"></div>
           {/* Static clouds for menu */}
           <div className="absolute top-20 left-20 w-32 h-16 bg-white/40 rounded-full blur-xl"></div>
           <div className="absolute top-40 right-40 w-48 h-20 bg-white/30 rounded-full blur-xl"></div>
        </div>
      )}
    </div>
  );
};

export default App;

