                    />
                  </div>
                );
              })}
            </div>
          </div>
        ))}

        <div className="p-4 bg-yellow-900/20 rounded border border-yellow-700/30 text-xs text-yellow-500">
           Note: Vehicle dimension changes (Width/Height/Wheel) only apply to the next car respawn or game restart.
        </div>
      </div>
    </div>
  );
