import React, { useState, useEffect, useRef } from 'react';
import { GameConfig } from '../types';
import { getTerrainNoise } from '../utils/physics';

interface MapMakerProps {
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onClose: () => void;
}

const MapMaker: React.FC<MapMakerProps> = ({ config, onUpdateConfig, onClose }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [points, setPoints] = useState<{x: number, y: number}[]>([]);

  // Sliders to control
  const controls = [
    { label: 'Base Frequency', key: 'TERRAIN_NOISE_FREQ_1', min: 0.01, max: 0.5, step: 0.01 },
    { label: 'Base Amplitude', key: 'TERRAIN_AMP_1', min: 0.1, max: 3.0, step: 0.1 },
    { label: 'Detail Frequency', key: 'TERRAIN_NOISE_FREQ_2', min: 0.01, max: 1.0, step: 0.01 },
    { label: 'Detail Amplitude', key: 'TERRAIN_AMP_2', min: 0.0, max: 2.0, step: 0.1 },
    { label: 'Rumble Frequency', key: 'TERRAIN_NOISE_FREQ_3', min: 0.01, max: 2.0, step: 0.01 },
    { label: 'Rumble Amplitude', key: 'TERRAIN_AMP_3', min: 0.0, max: 0.5, step: 0.01 },
  ];

  // Generate Preview Points
  useEffect(() => {
    const pts = [];
    const segments = 100;
    const width = 800; // Visual width
    // Simulate about 100 game segments
    let lastY = 0;

    for (let i = 0; i < segments; i++) {
        // We use the same physics logic, but we need to accumulate y changes like the physics engine does
        const noiseCurrent = getTerrainNoise(i, config);
        const noisePrev = getTerrainNoise(i - 1, config);
        const dy = -(noiseCurrent - noisePrev);

        lastY += dy;
        // Scale x for canvas fitting
        pts.push({ x: i * (width/segments), y: lastY });
    }
    setPoints(pts);
  }, [config]);

  // Render Canvas
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Grid
    ctx.strokeStyle = '#334155';
    ctx.beginPath();
    for(let i=0; i<canvas.width; i+=40) { ctx.moveTo(i,0); ctx.lineTo(i, canvas.height); }
    for(let i=0; i<canvas.height; i+=40) { ctx.moveTo(0,i); ctx.lineTo(canvas.width, i); }
    ctx.stroke();

    // Center line
    const centerY = canvas.height / 2;
    ctx.strokeStyle = '#94a3b8';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(0, centerY);
    ctx.lineTo(canvas.width, centerY);
    ctx.stroke();

    if (points.length < 2) return;

    // Draw Terrain
    ctx.strokeStyle = '#10b981';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(points[0].x, centerY + points[0].y);

    for(let i=1; i<points.length; i++) {
        ctx.lineTo(points[i].x, centerY + points[i].y);
    }
    ctx.stroke();

    // Fill Ground
    ctx.lineTo(points[points.length-1].x, canvas.height);
    ctx.lineTo(points[0].x, canvas.height);
    ctx.fillStyle = 'rgba(16, 185, 129, 0.2)';
    ctx.fill();

  }, [points]);

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(config, null, 2));
    alert("Map Config copied!");
  };

  return (
    <div className="absolute inset-0 z-50 bg-slate-900 text-white flex flex-col">
       <div className="p-4 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
            <h2 className="text-2xl font-bold">🗺️ Map Maker</h2>
            <div className="flex gap-4">
                 <button onClick={handleCopy} className="px-4 py-2 bg-blue-600 rounded font-bold hover:bg-blue-500">Copy Config</button>
                 <button onClick={onClose} className="px-4 py-2 bg-slate-600 rounded font-bold hover:bg-slate-500">Exit</button>
            </div>
       </div>

       <div className="flex-1 flex overflow-hidden">
            {/* Controls */}
            <div className="w-80 bg-slate-800 p-6 overflow-y-auto border-r border-slate-700 space-y-6">
                {controls.map((ctrl) => (
                    <div key={ctrl.key}>
                        <div className="flex justify-between text-sm mb-1 text-slate-300">
                            <label>{ctrl.label}</label>
                            <span className="font-mono text-blue-400">{config[ctrl.key as keyof GameConfig].toFixed(3)}</span>
                        </div>
                        <input 
                            type="range"
                            min={ctrl.min}
                            max={ctrl.max}
                            step={ctrl.step}
                            value={config[ctrl.key as keyof GameConfig]}
                            onChange={(e) => onUpdateConfig(ctrl.key as keyof GameConfig, parseFloat(e.target.value))}
                            className="w-full accent-blue-500 h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer"
                        />
                    </div>
                ))}

                <div className="bg-slate-700/50 p-4 rounded text-sm text-slate-400">
                    <p>Adjust the sliders to change the terrain generation algorithm. The preview shows a 100-segment slice.</p>
                </div>
            </div>

            {/* Preview */}
            <div className="flex-1 p-8 flex items-center justify-center bg-slate-900 relative">
                 <div className="absolute top-4 left-4 text-slate-500 font-mono text-sm">PREVIEW</div>
                 <canvas 
                    ref={canvasRef} 
                    width={800} 
                    height={600} 
                    className="bg-slate-950 border border-slate-700 rounded-lg shadow-2xl"
                 />
            </div>
       </div>
    </div>
  );
};

export default MapMaker;

import React, { useState } from 'react';
import { CarModel, GameConfig } from '../types';
import { GAME_CONFIG } from '../constants';

interface CarMakerProps {
  onClose: () => void;
}

const CarMaker: React.FC<CarMakerProps> = ({ onClose }) => {
  // Local state for the custom car being built
  const [car, setCar] = useState<CarModel>({
    id: 'custom-' + Date.now(),
    name: 'Custom Rider',
    color: '#ef4444',
    bodyColor: '#ef4444',
    wheelColor: '#1f2937',
    speed: 1.0,
    acceleration: 0.02,
    density: 0.004,
    friction: 1.0,
    driveTrain: 'RWD'
  });

  // Also allow tweaking dimensions locally for visual preview, though they are usually global GameConfig
  // For the purpose of "Copy as Text", we will export the CarModel JSON.

  const handleChange = (key: keyof CarModel, value: any) => {
    setCar(prev => ({ ...prev, [key]: value }));
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(car, null, 2));
    alert("Car JSON copied to clipboard!");
  };

  return (
    <div className="absolute inset-0 z-50 bg-slate-900 text-white flex flex-col">
       <div className="p-4 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
            <h2 className="text-2xl font-bold">🛠️ Car Maker</h2>
            <div className="flex gap-4">
                 <button onClick={handleCopy} className="px-4 py-2 bg-blue-600 rounded font-bold hover:bg-blue-500">Copy JSON</button>
                 <button onClick={onClose} className="px-4 py-2 bg-slate-600 rounded font-bold hover:bg-slate-500">Exit</button>
            </div>
       </div>

       <div className="flex-1 flex overflow-hidden">
            {/* Controls */}
            <div className="w-96 bg-slate-800 p-6 overflow-y-auto border-r border-slate-700 space-y-6">

                {/* Text Inputs */}
                <div>
                    <label className="text-xs font-bold text-slate-500 uppercase">Name</label>
                    <input 
                        type="text" 
                        value={car.name} 
                        onChange={(e) => handleChange('name', e.target.value)}
                        className="w-full bg-slate-900 border border-slate-600 rounded p-2 text-white mt-1"
                    />
                </div>

                {/* Colors */}
                <div className="space-y-4 border-b border-slate-700 pb-4">
                    <h3 className="text-sm font-bold text-slate-400">Colors</h3>
                    <div className="flex items-center justify-between">
                         <label className="text-sm">Body Color</label>
                         <input type="color" value={car.bodyColor} onChange={(e) => handleChange('bodyColor', e.target.value)} />
                    </div>
                    <div className="flex items-center justify-between">
                         <label className="text-sm">Wheel Color</label>
                         <input type="color" value={car.wheelColor} onChange={(e) => handleChange('wheelColor', e.target.value)} />
                    </div>
                </div>

                {/* Physics */}
                <div className="space-y-4">
                    <h3 className="text-sm font-bold text-slate-400">Physics</h3>

                    <RangeControl label="Speed" value={car.speed} min={0.5} max={2.0} step={0.1} onChange={(v) => handleChange('speed', v)} />
                    <RangeControl label="Acceleration" value={car.acceleration} min={0.01} max={0.05} step={0.001} onChange={(v) => handleChange('acceleration', v)} />
                    <RangeControl label="Density (Weight)" value={car.density} min={0.001} max={0.01} step={0.0005} onChange={(v) => handleChange('density', v)} />
                    <RangeControl label="Friction (Grip)" value={car.friction} min={0.1} max={2.0} step={0.1} onChange={(v) => handleChange('friction', v)} />

                    <div>
                        <label className="text-xs font-bold text-slate-500 uppercase">Drivetrain</label>
                        <select 
                            value={car.driveTrain}
                            onChange={(e) => handleChange('driveTrain', e.target.value)}
                            className="w-full bg-slate-900 border border-slate-600 rounded p-2 text-white mt-1"
                        >
                            <option value="RWD">RWD (Rear Wheel Drive)</option>
                            <option value="FWD">FWD (Front Wheel Drive)</option>
                            <option value="AWD">AWD (All Wheel Drive)</option>
                        </select>
                    </div>
                </div>
            </div>

            {/* Preview */}
            <div className="flex-1 p-8 flex flex-col items-center justify-center bg-slate-950 relative">
                 <div className="absolute top-4 left-4 text-slate-500 font-mono text-sm">PREVIEW</div>

                 <div className="scale-150 p-10 bg-sky-300 rounded-full shadow-inner flex items-center justify-center border-4 border-sky-400 relative overflow-hidden" style={{ width: 400, height: 400 }}>
                    {/* Fake Ground */}
                    <div className="absolute bottom-0 w-full h-1/3 bg-emerald-500 border-t-4 border-emerald-700"></div>

                    {/* Car Rendering (Simplified SVG based on props) */}
                    <svg width="200" height="100" viewBox="-100 -50 200 100" className="z-10 drop-shadow-xl">
                         <g transform="translate(0, 0)">
                             {/* Chassis */}
                             <path
                                d={`M -${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                                    L ${GAME_CONFIG.CAR_WIDTH/2} -${GAME_CONFIG.CAR_HEIGHT/2} 
                                    L ${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} 
                                    L -${GAME_CONFIG.CAR_WIDTH/2} ${GAME_CONFIG.CAR_HEIGHT/2} Z`}
                                fill={car.bodyColor}
                                stroke="rgba(0,0,0,0.5)"
                                strokeWidth="2"
                            />
                            {/* Wheels */}
                            <circle cx={-GAME_CONFIG.CAR_WIDTH/2.2 + GAME_CONFIG.WHEEL_SIZE} cy={GAME_CONFIG.CAR_HEIGHT/2} r={GAME_CONFIG.WHEEL_SIZE} fill={car.wheelColor} />
                            <circle cx={GAME_CONFIG.CAR_WIDTH/2.2 - GAME_CONFIG.WHEEL_SIZE} cy={GAME_CONFIG.CAR_HEIGHT/2} r={GAME_CONFIG.WHEEL_SIZE} fill={car.wheelColor} />
                         </g>
                    </svg>
                 </div>

                 <div className="mt-8 text-center text-slate-400 max-w-md">
                    <p className="text-sm">Use "Copy JSON" to save your car design.</p>
                 </div>
            </div>
       </div>
    </div>
  );
};

const RangeControl: React.FC<{ label: string; value: number; min: number; max: number; step: number; onChange: (v: number) => void }> = ({ label, value, min, max, step, onChange }) => (
    <div>
        <div className="flex justify-between text-sm mb-1 text-slate-300">
            <label>{label}</label>
            <span className="font-mono text-blue-400">{Number(value).toFixed(3)}</span>
        </div>
        <input 
            type="range"
            min={min}
            max={max}
            step={step}
            value={value}
            onChange={(e) => onChange(parseFloat(e.target.value))}
            className="w-full accent-blue-500 h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer"
        />
    </div>
);

export default CarMaker;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
  selectedCar: CarModel;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onResetConfig: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

const Game: React.FC<GameProps> = ({ onGameOver, selectedCar, config, onUpdateConfig, onResetConfig }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); // Count how many wheels are touching ground

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events for Game Logic
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            if ((isChassisA && isGroundB) || (isChassisB && isGroundA)) {
                const chassisBody = isChassisA ? bodyA : bodyB;

                // Use contact points to determine if it's the upper part (roof) of the car
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;

                        // Rotate point to match chassis local space (up is negative Y in local space)
                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedY = localX * sin + localY * cos;

                        // If rotatedY is < -10, it implies contact is on the upper half/roof.
                        if (rotatedY < -10) {
                            gameStateRef.current.isGameOver = true;
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += config.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic
            let wheelBody = null;
            if (isWheelA && isGroundB) wheelBody = bodyA;
            if (isWheelB && isGroundA) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2);
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    const CONFIG = config;

    // Day/Night Cycle
    gameTimeRef.current = (gameTimeRef.current + 1) % CONFIG.DAY_CYCLE_FRAMES;
    const cyclePos = gameTimeRef.current / CONFIG.DAY_CYCLE_FRAMES;

    let skyTop = COLORS.skyStart;
    let skyBot = COLORS.skyEnd;

    if (cyclePos > 0.4 && cyclePos <= 0.5) {
        const t = (cyclePos - 0.4) * 10;
        skyTop = interpolateColor(COLORS.skyStart, COLORS.skyNightStart, t);
        skyBot = interpolateColor(COLORS.skyEnd, COLORS.skyNightEnd, t);
    } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
        skyTop = COLORS.skyNightStart;
        skyBot = COLORS.skyNightEnd;
    } else if (cyclePos > 0.9) {
        const t = (cyclePos - 0.9) * 10;
        skyTop = interpolateColor(COLORS.skyNightStart, COLORS.skyStart, t);
        skyBot = interpolateColor(COLORS.skyNightEnd, COLORS.skyEnd, t);
    }

    isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

    if (containerRef.current) {
        containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
    }

    Matter.Engine.update(engine, 1000 / 60);

    // --- CAR PHYSICS LOGIC ---
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = selectedCar.speed; 
    const acceleration = selectedCar.acceleration;

    const isGrounded = wheelGroundContacts.current > 0;

    const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
    const maxRotation = CONFIG.MAX_ROTATION_SPEED;
    const brakeRotationFactor = 0.5;

    // Helper to apply speed based on drivetrain
    const applyPower = (targetSpeed: number) => {
        if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
        }
        if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
        }
    };

    if (keys.right) {
      // GAS -> Nose Up (CCW, Negative)
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
      }

      if (chassis.angularVelocity > -maxRotation) {
         Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
      }

    } else if (keys.left) {
      // BRAKE -> Nose Down (CW, Positive)
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
      }

      if (chassis.angularVelocity < maxRotation) {
        Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
      }
    }

    // --- RENDER ---
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // Chunk Loading
    const carX = chassis.position.x;
    if (carX > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Wall Update
    const wallTargetX = carX - CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // Particles
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2;
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config]);

  // Decoration Rendering
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  {/* Post */}
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  {/* Head */}
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  {/* Light Source */}
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  {/* Glow */}
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds, config.COIN_SIZE]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Debug Toggle */}
      <div className="absolute top-4 right-4 z-30">
          <button 
            onClick={() => setIsDebugOpen(!isDebugOpen)}
            className="w-10 h-10 bg-slate-800/80 backdrop-blur text-white rounded-lg border border-slate-600 flex items-center justify-center hover:bg-slate-700 transition"
          >
             ⚙️
          </button>
      </div>

      {isDebugOpen && (
          <DebugMenu 
             config={config} 
             onUpdate={onUpdateConfig} 
             onClose={() => setIsDebugOpen(false)} 
             onReset={onResetConfig}
          />
      )}

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-black/60 active:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-black/60 active:bg-emerald-900/60 shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        <g>
            {Array.from({ length: config.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} 
                L -${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} Z`}
            fill={selectedCar.bodyColor}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

import React, { useState, useEffect } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import CarSelection from './components/CarSelection';
import MapMaker from './components/MapMaker';
import CarMaker from './components/CarMaker';
import { GameState, CarModel, GameConfig } from './types';
import { CAR_MODELS, GAME_CONFIG } from './constants';

const CONFIG_STORAGE_KEY = 'hill_climber_config_v1';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  // Game Configuration State (Persisted)
  const [gameConfig, setGameConfig] = useState<GameConfig>(GAME_CONFIG);

  // Car Selection State
  const [selectedCar, setSelectedCar] = useState<CarModel>(CAR_MODELS[0]);
  const [isGarageOpen, setIsGarageOpen] = useState(false);

  // Load Config on Mount
  useEffect(() => {
    const savedConfig = localStorage.getItem(CONFIG_STORAGE_KEY);
    if (savedConfig) {
        try {
            const parsed = JSON.parse(savedConfig);
            // Merge with default to ensure new keys exist if schema updates
            setGameConfig(prev => ({ ...prev, ...parsed }));
        } catch (e) {
            console.error("Failed to load config", e);
        }
    }
  }, []);

  // Save Config on Change
  useEffect(() => {
    localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(gameConfig));
  }, [gameConfig]);

  const updateConfig = (key: keyof GameConfig, value: number) => {
      setGameConfig(prev => ({ ...prev, [key]: value }));
  };

  const resetConfig = () => {
      setGameConfig(GAME_CONFIG);
  };

  const startGame = () => {
    setScore(0);
    setCoins(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  const handleCarSelect = (car: CarModel) => {
    setSelectedCar(car);
  };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu 
          onStart={startGame} 
          onOpenGarage={() => setIsGarageOpen(true)}
          onOpenMapMaker={() => setGameState(GameState.MAP_MAKER)}
          onOpenCarMaker={() => setGameState(GameState.CAR_MAKER)}
          bestDistance={bestScore} 
        />
      )}

      {gameState === GameState.PLAYING && (
        <Game 
            onGameOver={handleGameOver} 
            selectedCar={selectedCar} 
            config={gameConfig}
            onUpdateConfig={updateConfig}
            onResetConfig={resetConfig}
        />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {gameState === GameState.MAP_MAKER && (
          <MapMaker 
             config={gameConfig} 
             onUpdateConfig={updateConfig} 
             onClose={() => setGameState(GameState.MENU)} 
          />
      )}

      {gameState === GameState.CAR_MAKER && (
          <CarMaker onClose={() => setGameState(GameState.MENU)} />
      )}

      {isGarageOpen && (
        <CarSelection 
          currentCarId={selectedCar.id} 
          onSelect={handleCarSelect} 
          onClose={() => setIsGarageOpen(false)} 
        />
      )}

      {/* Background for Menu/GameOver states to look nice even without the game running */}
      {gameState !== GameState.PLAYING && gameState !== GameState.MAP_MAKER && gameState !== GameState.CAR_MAKER && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-sky-500 to-sky-200">
           <div className="absolute bottom-0 w-full h-1/3 bg-emerald-600 transform skew-y-3 origin-bottom-right"></div>
           <div className="absolute bottom-0 w-full h-1/4 bg-emerald-500 transform -skew-y-2 origin-bottom-left"></div>
           {/* Static clouds for menu */}
           <div className="absolute top-20 left-20 w-32 h-16 bg-white/40 rounded-full blur-xl"></div>
           <div className="absolute top-40 right-40 w-48 h-20 bg-white/30 rounded-full blur-xl"></div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
  selectedCar: CarModel;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onResetConfig: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

interface StuntState {
    inAir: boolean;
    startAngle: number;
    flips: number;
}

const Game: React.FC<GameProps> = ({ onGameOver, selectedCar, config, onUpdateConfig, onResetConfig }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); // Count how many wheels are touching ground
  const stuntRef = useRef<StuntState>({ inAir: false, startAngle: 0, flips: 0 });

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // UI Notification State
  const [notification, setNotification] = useState<{text: string, id: number} | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      const newClouds = generateClouds(startX, length);
      setClouds(prev => [...prev, ...newClouds]);

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events for Game Logic
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            if ((isChassisA && isGroundB) || (isChassisB && isGroundA)) {
                const chassisBody = isChassisA ? bodyA : bodyB;

                // Use contact points to determine if it's the upper part (roof) of the car
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;

                        // Rotate point to match chassis local space 
                        // Angle in Matter is clockwise radians.
                        // x' = x cos θ + y sin θ
                        // y' = -x sin θ + y cos θ  <-- this is if we rotate the POINT.
                        // But we want to rotate the coordinate system, which is inverse.

                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedX = localX * cos - localY * sin;
                        const rotatedY = localX * sin + localY * cos;

                        // Check if touching top surface (rotatedY < -10) 
                        // AND in the middle section (Math.abs(rotatedX) < 40)
                        // This prevents death when scraping bumpers or front/back only.
                        if (rotatedY < -10 && Math.abs(rotatedX) < 40) {
                            gameStateRef.current.isGameOver = true;
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Coin Logic
            const isCarA = bodyA.label === 'chassis' || bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isCarB = bodyB.label === 'chassis' || bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';

            let coinBody = null;
            if (isCarA && bodyB.label === 'coin') coinBody = bodyB;
            if (isCarB && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound();
                gameStateRef.current.coins += config.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic
            let wheelBody = null;
            if (isWheelA && isGroundB) wheelBody = bodyA;
            if (isWheelB && isGroundA) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2);
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
      if (soundManagerRef.current) soundManagerRef.current.resume();
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    const CONFIG = config;

    // Day/Night Cycle
    gameTimeRef.current = (gameTimeRef.current + 1) % CONFIG.DAY_CYCLE_FRAMES;
    const cyclePos = gameTimeRef.current / CONFIG.DAY_CYCLE_FRAMES;

    let skyTop = COLORS.skyStart;
    let skyBot = COLORS.skyEnd;

    if (cyclePos > 0.4 && cyclePos <= 0.5) {
        const t = (cyclePos - 0.4) * 10;
        skyTop = interpolateColor(COLORS.skyStart, COLORS.skyNightStart, t);
        skyBot = interpolateColor(COLORS.skyEnd, COLORS.skyNightEnd, t);
    } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
        skyTop = COLORS.skyNightStart;
        skyBot = COLORS.skyNightEnd;
    } else if (cyclePos > 0.9) {
        const t = (cyclePos - 0.9) * 10;
        skyTop = interpolateColor(COLORS.skyNightStart, COLORS.skyStart, t);
        skyBot = interpolateColor(COLORS.skyNightEnd, COLORS.skyEnd, t);
    }

    isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

    if (containerRef.current) {
        containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
    }

    Matter.Engine.update(engine, 1000 / 60);

    // --- CAR PHYSICS LOGIC ---
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = selectedCar.speed; 
    const acceleration = selectedCar.acceleration;

    const isGrounded = wheelGroundContacts.current > 0;

    const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
    const maxRotation = CONFIG.MAX_ROTATION_SPEED;
    const brakeRotationFactor = 0.5;

    // Stunt Logic
    if (isGrounded) {
       // Just landed?
       if (stuntRef.current.inAir) {
           const flips = stuntRef.current.flips;
           if (flips > 0 && !gameStateRef.current.isGameOver) {
               // Award Bonus
               const bonus = flips * 1000;
               gameStateRef.current.coins += bonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;

               // Show Notification
               setNotification({ text: `${flips > 1 ? 'DOUBLE ' : ''}FLIP! +${bonus}`, id: Date.now() });
               setTimeout(() => setNotification(null), 2500);

               // Sound
               soundManagerRef.current?.playCoinSound();
           }
           stuntRef.current = { inAir: false, startAngle: 0, flips: 0 };
       }
    } else {
       if (!stuntRef.current.inAir) {
           // Takeoff
           stuntRef.current.inAir = true;
           stuntRef.current.startAngle = chassis.angle;
           stuntRef.current.flips = 0;
       } else {
           // In Air - Check rotation
           const diff = Math.abs(chassis.angle - stuntRef.current.startAngle);
           const currentFlips = Math.floor(diff / (2 * Math.PI));
           if (currentFlips > stuntRef.current.flips) {
               stuntRef.current.flips = currentFlips;
           }
       }
    }

    // Helper to apply speed based on drivetrain
    const applyPower = (targetSpeed: number) => {
        if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
        }
        if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
        }
    };

    if (keys.right) {
      // GAS -> Nose Up (CCW, Negative)
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
      }

      if (chassis.angularVelocity > -maxRotation) {
         Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
      }

    } else if (keys.left) {
      // BRAKE -> Nose Down (CW, Positive)
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
      }

      if (chassis.angularVelocity < maxRotation) {
        Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
      }
    }

    // --- RENDER ---
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // Chunk Loading
    const carX = chassis.position.x;
    if (carX > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Wall Update
    const wallTargetX = carX - CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // Particles
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2;
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : COLORS.particleDust);
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);
    }

    // HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config]);

  // Decoration Rendering
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  {/* Post */}
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  {/* Head */}
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  {/* Light Source */}
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  {/* Glow */}
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={COLORS.groundDark} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds, config.COIN_SIZE]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-gradient-to-b from-sky-400 to-sky-100 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Floating Notification */}
      {notification && (
          <div className="absolute top-32 left-1/2 transform -translate-x-1/2 z-40 animate-bounce">
              <div className="text-4xl font-black text-yellow-400 drop-shadow-[0_4px_4px_rgba(0,0,0,0.5)] italic">
                  {notification.text}
              </div>
          </div>
      )}

      {/* Debug Toggle */}
      <div className="absolute top-4 right-4 z-30">
          <button 
            onClick={() => setIsDebugOpen(!isDebugOpen)}
            className="w-10 h-10 bg-slate-800/80 backdrop-blur text-white rounded-lg border border-slate-600 flex items-center justify-center hover:bg-slate-700 transition"
          >
             ⚙️
          </button>
      </div>

      {isDebugOpen && (
          <DebugMenu 
             config={config} 
             onUpdate={onUpdateConfig} 
             onClose={() => setIsDebugOpen(false)} 
             onReset={onResetConfig}
          />
      )}

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-black/60 active:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-black/60 active:bg-emerald-900/60 shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; if(soundManagerRef.current) soundManagerRef.current.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={COLORS.ground} />
                <circle cx="10" cy="10" r="2" fill={COLORS.groundDark} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={COLORS.groundDark} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={COLORS.groundDark} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={COLORS.groundDark} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        <g>
            {Array.from({ length: config.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} 
                L -${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} Z`}
            fill={selectedCar.bodyColor}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  MAP_MAKER = 'MAP_MAKER',
  CAR_MAKER = 'CAR_MAKER',
}

export interface GameScore {
  distance: number;
  bestDistance: number;
}

export interface CarModel {
  id: string;
  name: string;
  color: string; // Main display color
  bodyColor: string; // Hex for the chassis
  wheelColor: string;
  speed: number; // Max angular velocity
  acceleration: number; // Torque increment
  density: number; // Weight/Stability
  friction: number; // Grip
  driveTrain: 'FWD' | 'RWD' | 'AWD'; // New property for powered wheels
}

