  id: string;
  name: string;
  description: string;
  backgroundType: 'earth' | 'moon';
  skyColorStart: string;
  skyColorEnd: string;
  groundColor: string;
  groundDarkColor: string;
  particleColor: string;
  configOverrides: Partial<GameConfig>;
}

