import React, { useState, useEffect } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import CarSelection from './components/CarSelection';
import MapSelection from './components/MapSelection';
import MapMaker from './components/MapMaker';
import CarMaker from './components/CarMaker';
import { GameState, CarModel, GameConfig, MapConfig } from './types';
import { CAR_MODELS, GAME_CONFIG, MAPS } from './constants';

const CONFIG_STORAGE_KEY = 'hill_climber_config_v1';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  // Game Configuration State (Persisted)
  const [gameConfig, setGameConfig] = useState<GameConfig>(GAME_CONFIG);

  // Selection State
  const [selectedCar, setSelectedCar] = useState<CarModel>(CAR_MODELS[0]);
  const [selectedMap, setSelectedMap] = useState<MapConfig>(MAPS[0]);

  const [isGarageOpen, setIsGarageOpen] = useState(false);
  const [isMapSelectOpen, setIsMapSelectOpen] = useState(false);

  // Load Config on Mount
  useEffect(() => {
    const savedConfig = localStorage.getItem(CONFIG_STORAGE_KEY);
    if (savedConfig) {
        try {
            const parsed = JSON.parse(savedConfig);
            setGameConfig(prev => ({ ...prev, ...parsed }));
        } catch (e) {
            console.error("Failed to load config", e);
        }
    }
  }, []);

  // Save Config on Change
  useEffect(() => {
    localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(gameConfig));
  }, [gameConfig]);

  const updateConfig = (key: keyof GameConfig, value: number) => {
      setGameConfig(prev => ({ ...prev, [key]: value }));
  };

  const resetConfig = () => {
      setGameConfig(GAME_CONFIG);
  };

  const startGame = () => {
    setScore(0);
    setCoins(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  // Merge Base Config with Map Overrides for the active game session
  const activeConfig = { ...gameConfig, ...selectedMap.configOverrides };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu 
          onStart={startGame} 
          onOpenGarage={() => setIsGarageOpen(true)}
          onOpenMapSelect={() => setIsMapSelectOpen(true)}
          onOpenMapMaker={() => setGameState(GameState.MAP_MAKER)}
          onOpenCarMaker={() => setGameState(GameState.CAR_MAKER)}
          bestDistance={bestScore} 
        />
      )}

      {gameState === GameState.PLAYING && (
        <Game 
            onGameOver={handleGameOver} 
            selectedCar={selectedCar} 
            selectedMap={selectedMap}
            config={activeConfig}
            onUpdateConfig={updateConfig}
            onResetConfig={resetConfig}
        />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {gameState === GameState.MAP_MAKER && (
          <MapMaker 
             config={activeConfig} 
             onUpdateConfig={updateConfig} 
             onClose={() => setGameState(GameState.MENU)} 
          />
      )}

      {gameState === GameState.CAR_MAKER && (
          <CarMaker onClose={() => setGameState(GameState.MENU)} />
      )}

      {isGarageOpen && (
        <CarSelection 
          currentCarId={selectedCar.id} 
          onSelect={setSelectedCar} 
          onClose={() => setIsGarageOpen(false)} 
        />
      )}

      {isMapSelectOpen && (
        <MapSelection 
          currentMapId={selectedMap.id} 
          onSelect={setSelectedMap} 
          onClose={() => setIsMapSelectOpen(false)} 
        />
      )}

      {/* Background for Menu/GameOver states */}
      {gameState !== GameState.PLAYING && gameState !== GameState.MAP_MAKER && gameState !== GameState.CAR_MAKER && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b" style={{ 
            backgroundImage: `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})` 
        }}>
           <div className="absolute bottom-0 w-full h-1/3 transform skew-y-3 origin-bottom-right" style={{ backgroundColor: selectedMap.groundDarkColor }}></div>
           <div className="absolute bottom-0 w-full h-1/4 transform -skew-y-2 origin-bottom-left" style={{ backgroundColor: selectedMap.groundColor }}></div>
        </div>
      )}
    </div>
  );
};

export default App;

export class SoundManager {
    private audioContext: AudioContext | null = null;
    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    // Air Sound State
    private airGainNode: GainNode | null = null;
    private isAirSoundPlaying: boolean = false;

    constructor() {
      if (typeof window !== 'undefined') {
        const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
        if (AudioContextClass) {
          this.audioContext = new AudioContextClass();
        }
      }
    }

    public resume() {
      if (this.audioContext && this.audioContext.state === 'suspended') {
        this.audioContext.resume().catch(e => console.error("Audio resume failed", e));
      }
    }

    public playCoinSound() {
      if (!this.audioContext) return;
      this.resume();

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      const scale = [523.25, 587.33, 659.25, 698.46, 783.99, 880.00, 987.77, 1046.50]; // C5 Scale
      const frequency = scale[this.coinStep % scale.length];
      const octaveMultiplier = Math.pow(2, Math.floor(this.coinStep / 8));
      const finalFreq = frequency * (octaveMultiplier > 2 ? 2 : octaveMultiplier);

      const osc = this.audioContext.createOscillator();
      const gain = this.audioContext.createGain();

      osc.type = 'sine';
      osc.frequency.setValueAtTime(finalFreq, this.audioContext.currentTime);

      // Sharper Ping
      gain.gain.setValueAtTime(0, this.audioContext.currentTime);
      gain.gain.linearRampToValueAtTime(0.3, this.audioContext.currentTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.001, this.audioContext.currentTime + 0.4);

      osc.connect(gain);
      gain.connect(this.audioContext.destination);

      osc.start();
      osc.stop(this.audioContext.currentTime + 0.4);

      this.coinStep++;
    }

    public playFlipSound() {
        if (!this.audioContext) return;
        this.resume();

        const osc = this.audioContext.createOscillator();
        const gain = this.audioContext.createGain();

        // "Thang" sound - Low Triangle wave dropping in pitch
        osc.type = 'triangle';
        osc.frequency.setValueAtTime(150, this.audioContext.currentTime);
        osc.frequency.exponentialRampToValueAtTime(40, this.audioContext.currentTime + 0.8);

        gain.gain.setValueAtTime(0.5, this.audioContext.currentTime);
        gain.gain.exponentialRampToValueAtTime(0.001, this.audioContext.currentTime + 0.8);

        osc.connect(gain);
        gain.connect(this.audioContext.destination);

        osc.start();
        osc.stop(this.audioContext.currentTime + 0.8);
    }

    public startAirSound() {
        if (!this.audioContext || this.isAirSoundPlaying) return;
        this.resume();

        // Create White Noise
        const bufferSize = this.audioContext.sampleRate * 2; // 2 seconds buffer
        const buffer = this.audioContext.createBuffer(1, bufferSize, this.audioContext.sampleRate);
        const data = buffer.getChannelData(0);
        for (let i = 0; i < bufferSize; i++) {
            data[i] = Math.random() * 2 - 1;
        }

        const noise = this.audioContext.createBufferSource();
        noise.buffer = buffer;
        noise.loop = true;

        // Filter to make it sound like wind (Low Pass)
        const filter = this.audioContext.createBiquadFilter();
        filter.type = 'lowpass';
        filter.frequency.value = 400;

        const gain = this.audioContext.createGain();
        gain.gain.value = 0; // Start silent and fade in

        noise.connect(filter);
        filter.connect(gain);
        gain.connect(this.audioContext.destination);

        noise.start();

        // Fade in
        gain.gain.linearRampToValueAtTime(0.15, this.audioContext.currentTime + 0.5);

        this.airGainNode = gain;
        this.isAirSoundPlaying = true;
    }

    public stopAirSound() {
        if (!this.audioContext || !this.isAirSoundPlaying || !this.airGainNode) return;

        const gain = this.airGainNode;
        // Fade out
        gain.gain.cancelScheduledValues(this.audioContext.currentTime);
        gain.gain.linearRampToValueAtTime(0, this.audioContext.currentTime + 0.3);

        setTimeout(() => {
            // Check if we didn't start playing again in the meantime
            if (this.airGainNode === gain) {
                 this.isAirSoundPlaying = false;
                 this.airGainNode = null;
            }
        }, 350);
    }
}

