    // Continuous Sound Nodes
    private engineOsc: OscillatorNode | null = null;
    private engineGain: GainNode | null = null;

    private windSource: AudioBufferSourceNode | null = null;
    private windGain: GainNode | null = null;

    private tireSource: AudioBufferSourceNode | null = null;
    private tireGain: GainNode | null = null;

    private isInitialized: boolean = false;

    constructor() {
      // Lazy init called on first interaction usually, but we set up structure
    }

    private init() {
        if (typeof window === 'undefined') return;

        if (!SoundManager.audioContext) {
            const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
            if (AudioContextClass) {
                const ctx = new AudioContextClass();
                SoundManager.audioContext = ctx;

                // 1. Master Gain - Increased slightly based on request
                const masterGain = ctx.createGain();
                masterGain.gain.value = 0.25; 
                SoundManager.masterGain = masterGain;

                // 2. Analyser
                const analyser = ctx.createAnalyser();
                analyser.fftSize = 256; 
                SoundManager.analyser = analyser;
                SoundManager.dataArray = new Uint8Array(analyser.frequencyBinCount);

                masterGain.connect(analyser);
                analyser.connect(ctx.destination);

                // Create Noise Buffers once
                this.createNoiseBuffer('white', ctx);
                this.createNoiseBuffer('brown', ctx);
            }
        }

        if (SoundManager.audioContext && !this.isInitialized) {
            this.setupContinuousSounds();
            this.isInitialized = true;
        }
    }

    private createNoiseBuffer(type: 'white' | 'brown', ctx: AudioContext) {
        if (SoundManager.bufferCache.has(type)) return;

        const bufferSize = ctx.sampleRate * 2; // 2 seconds
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);

        for (let i = 0; i < bufferSize; i++) {
            if (type === 'white') {
                data[i] = Math.random() * 2 - 1;
            } else {
                // Brown noise approximation
                const white = Math.random() * 2 - 1;
                data[i] = (lastOut + (0.02 * white)) / 1.02;
                lastOut = data[i];
                data[i] *= 3.5; // Compensate for gain loss
            }
        }
        SoundManager.bufferCache.set(type, buffer);
    }

    private setupContinuousSounds() {
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // --- ENGINE ---
        this.engineOsc = ctx.createOscillator();
        this.engineOsc.type = 'sawtooth';
        this.engineOsc.frequency.value = 60;

        // Engine Filter (Lowpass to muffle the harsh saw)
        const engineFilter = ctx.createBiquadFilter();
        engineFilter.type = 'lowpass';
        engineFilter.frequency.value = 400;

        this.engineGain = ctx.createGain();
        this.engineGain.gain.value = 0;

        this.engineOsc.connect(engineFilter);
        engineFilter.connect(this.engineGain);
        this.engineGain.connect(master);
        this.engineOsc.start();

        // --- WIND (In Air) ---
        const whiteBuffer = SoundManager.bufferCache.get('white');
        if (whiteBuffer) {
            this.windSource = ctx.createBufferSource();
            this.windSource.buffer = whiteBuffer;
            this.windSource.loop = true;

            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 600;

            this.windGain = ctx.createGain();
            this.windGain.gain.value = 0;

            this.windSource.connect(windFilter);
            windFilter.connect(this.windGain);
            this.windGain.connect(master);
            this.windSource.start();
        }

        // --- TIRES (On Ground) ---
        const brownBuffer = SoundManager.bufferCache.get('brown');
        if (brownBuffer) {
            this.tireSource = ctx.createBufferSource();
            this.tireSource.buffer = brownBuffer;
            this.tireSource.loop = true;

            this.tireGain = ctx.createGain();
            this.tireGain.gain.value = 0;

            this.tireSource.connect(this.tireGain);
            this.tireGain.connect(master);
            this.tireSource.start();
        }
    }

    public resume() {
      const ctx = SoundManager.audioContext;
      if (!ctx) {
          this.init();
          return;
      }
      if (ctx.state === 'suspended' || (ctx.state as string) === 'interrupted') {
        ctx.resume();
      }
      if (!this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
    }

    public updateContinuous(speedRatio: number, isGrounded: boolean, isGasPressed: boolean) {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Clamp speed ratio 0-1 (approx)
        const speed = Math.max(0, Math.min(1, Math.abs(speedRatio)));

        // --- ENGINE ---
        if (this.engineOsc && this.engineGain) {
            // Pitch: 80Hz idle -> 300Hz max
            const targetFreq = 80 + (speed * 220) + (isGasPressed ? 50 : 0);
            this.engineOsc.frequency.setTargetAtTime(targetFreq, t, 0.1);

            // Volume: Idle 0.1, Moving/Gas 0.3
            const targetGain = 0.1 + (speed * 0.1) + (isGasPressed ? 0.1 : 0);
            this.engineGain.gain.setTargetAtTime(targetGain, t, 0.1);
        }

        // --- TIRES ---
        if (this.tireGain) {
            // Only audible when grounded and moving
            const tireVol = isGrounded && speed > 0.1 ? Math.min(0.2, speed * 0.3) : 0;
            this.tireGain.gain.setTargetAtTime(tireVol, t, 0.1);
        }

        // --- WIND ---
        if (this.windGain) {
            // Audible when moving fast, louder in air
            let windVol = speed * 0.15;
            if (!isGrounded) windVol += 0.15; // Boost in air
            if (speed < 0.1) windVol = 0;

            this.windGain.gain.setTargetAtTime(windVol, t, 0.2);
        }
    }

    public getAudioLevel(): number {
        if (!SoundManager.analyser || !SoundManager.dataArray) return 0;
        SoundManager.analyser.getByteTimeDomainData(SoundManager.dataArray);

        let sum = 0;
        for (let i = 0; i < SoundManager.dataArray.length; i++) {
            const amplitude = (SoundManager.dataArray[i] - 128) / 128;
            sum += amplitude * amplitude;
        }

        const rms = Math.sqrt(sum / SoundManager.dataArray.length);
        // Adjusted sensitivity
        return Math.min(1.0, rms * 10); 
    }

    public playCoinSound() {
      if (!SoundManager.audioContext) this.init();
      const ctx = SoundManager.audioContext;
      const master = SoundManager.masterGain;
      if (!ctx || !master) return;

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      const scale = [523.25, 587.33, 659.25, 698.46, 783.99, 880.00, 987.77, 1046.50]; 
      const frequency = scale[this.coinStep % scale.length];

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine'; // Changed back to sine for less harshness
      osc.frequency.setValueAtTime(frequency, ctx.currentTime);

      // Lower individual gain
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.05); 
      gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.4);

      osc.connect(gain);
      gain.connect(master);

      osc.start();
      osc.stop(ctx.currentTime + 0.45);

      this.coinStep++;
    }

    public playFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'triangle'; 
        osc.frequency.setValueAtTime(300, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.3);

        gain.gain.setValueAtTime(0.15, ctx.currentTime); // Reduced gain
        gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

        osc.connect(gain);
        gain.connect(master);

        osc.start();
        osc.stop(ctx.currentTime + 0.35);
    }

    public playDoubleFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // Major Third Arpeggio
        const notes = [600, 750, 900];
        const now = ctx.currentTime;

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = 'square';
            osc.frequency.value = freq;

            const start = now + (i * 0.1);
            gain.gain.setValueAtTime(0, start);
            gain.gain.linearRampToValueAtTime(0.1, start + 0.05);
            gain.gain.linearRampToValueAtTime(0, start + 0.3);

            osc.connect(gain);
            gain.connect(master);
            osc.start(start);
            osc.stop(start + 0.4);
        });
    }

    // Deprecated single purpose air sound, now handled by updateContinuous
    public startAirSound() {} 
    public stopAirSound() {}
}

// Global variable for Brown noise filter state
let lastOut = 0;

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onResetConfig: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

interface StuntState {
    inAir: boolean;
    startAngle: number;
    flips: number;
    airTime: number;
}

const Game: React.FC<GameProps> = ({ onGameOver, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); // Count how many wheels are touching ground
  const stuntRef = useRef<StuntState>({ inAir: false, startAngle: 0, flips: 0, airTime: 0 });

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // UI Notification State
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);
  const backgroundLayerRef = useRef<SVGGElement>(null);

  // Sound Bar Ref
  const soundBarRef = useRef<HTMLDivElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [stars, setStars] = useState<{x: number, y: number, r: number, opacity: number}[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Generate static stars for Moon map
  useEffect(() => {
      if (selectedMap.backgroundType === 'moon') {
          const s = [];
          for(let i=0; i<100; i++) {
              s.push({
                  x: Math.random() * 2000,
                  y: Math.random() * 1000 - 500,
                  r: Math.random() * 2,
                  opacity: Math.random()
              });
          }
          setStars(s);
      } else {
          setStars([]);
      }
  }, [selectedMap]);

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Clouds only for Earth
      if (selectedMap.backgroundType === 'earth') {
          const newClouds = generateClouds(startX, length);
          setClouds(prev => [...prev, ...newClouds]);
      }

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config, selectedMap.backgroundType]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events for Game Logic
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            if ((isChassisA && isGroundB) || (isChassisB && isGroundA)) {
                const chassisBody = isChassisA ? bodyA : bodyB;
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;
                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedX = localX * cos - localY * sin;
                        const rotatedY = localX * sin + localY * cos;

                        if (rotatedY < -10 && Math.abs(rotatedX) < 40) {
                            gameStateRef.current.isGameOver = true;
                            // Reset engine sound on game over
                            soundManagerRef.current?.updateContinuous(0, true, false);
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Coin Logic
            let coinBody = null;
            const isCar = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);
            if (isCar(bodyA) && bodyB.label === 'coin') coinBody = bodyB;
            if (isCar(bodyB) && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                Matter.World.remove(engine.world, coinBody);
                soundManagerRef.current?.playCoinSound(); // Trigger sound
                gameStateRef.current.coins += config.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic
            let wheelBody = null;
            if (isWheelA && isGroundB) wheelBody = bodyA;
            if (isWheelB && isGroundA) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
      // Stop continuous sounds on unmount
      soundManagerRef.current?.updateContinuous(0, true, false);
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2);
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Ensure Audio Context is resumed on first user interaction
  useEffect(() => {
    const handleInput = () => {
        soundManagerRef.current?.resume();
    };

    window.addEventListener('keydown', handleInput);
    window.addEventListener('mousedown', handleInput);
    window.addEventListener('touchstart', handleInput);

    return () => {
        window.removeEventListener('keydown', handleInput);
        window.removeEventListener('mousedown', handleInput);
        window.removeEventListener('touchstart', handleInput);
    };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // Update Sound Bar
    if (soundManagerRef.current && soundBarRef.current) {
        const level = soundManagerRef.current.getAudioLevel();
        const height = Math.min(100, level * 300); 
        soundBarRef.current.style.height = `${height}%`;
        soundBarRef.current.style.opacity = height > 2 ? '1' : '0.3';
    }

    const CONFIG = config;

    // Day/Night Cycle
    if (selectedMap.backgroundType === 'earth') {
        gameTimeRef.current = (gameTimeRef.current + 1) % CONFIG.DAY_CYCLE_FRAMES;
        const cyclePos = gameTimeRef.current / CONFIG.DAY_CYCLE_FRAMES;

        let skyTop = selectedMap.skyColorStart;
        let skyBot = selectedMap.skyColorEnd;

        if (cyclePos > 0.4 && cyclePos <= 0.5) {
            const t = (cyclePos - 0.4) * 10;
            skyTop = interpolateColor(selectedMap.skyColorStart, COLORS.skyNightStart, t);
            skyBot = interpolateColor(selectedMap.skyColorEnd, COLORS.skyNightEnd, t);
        } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
            skyTop = COLORS.skyNightStart;
            skyBot = COLORS.skyNightEnd;
        } else if (cyclePos > 0.9) {
            const t = (cyclePos - 0.9) * 10;
            skyTop = interpolateColor(COLORS.skyNightStart, selectedMap.skyColorStart, t);
            skyBot = interpolateColor(COLORS.skyNightEnd, selectedMap.skyColorEnd, t);
        }

        isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

        if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
        }
    } else {
        // Static background for Moon
         if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})`;
        }
    }

    Matter.Engine.update(engine, 1000 / 60);

    // --- CAR PHYSICS LOGIC ---
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = selectedCar.speed; 
    const acceleration = selectedCar.acceleration;

    const isGrounded = wheelGroundContacts.current > 0;

    // --- AUDIO UPDATE ---
    if (soundManagerRef.current && chassis) {
        // Calculate approx speed ratio for audio
        // Typical max angular velocity is around 1.0 - 2.0 rad/s in Physics config
        // Body velocity is roughly related.
        const speed = Matter.Vector.magnitude(chassis.velocity);
        const speedRatio = Math.min(1.5, speed / 25); // Normalize approx

        soundManagerRef.current.updateContinuous(
            speedRatio, 
            isGrounded, 
            keys.right
        );
    }

    const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
    const maxRotation = CONFIG.MAX_ROTATION_SPEED;
    const brakeRotationFactor = 0.5;

    // Stunt & Air Time Logic
    if (isGrounded) {
       // Just landed?
       if (stuntRef.current.inAir) {

           // Check Air Time Bonus
           // 60 frames = 1 second. Give bonus if > 1s
           if (stuntRef.current.airTime > 60) {
               const seconds = (stuntRef.current.airTime / 60).toFixed(1);
               const airBonus = Math.floor(stuntRef.current.airTime * 50); // Points per frame

               // Combine with flip bonus if any
               const flips = stuntRef.current.flips;
               let totalBonus = airBonus;
               let text = `AIR TIME ${seconds}s`;
               let subText = `+$${airBonus}`;

               if (flips > 0) {
                   const flipBonus = flips * 1000;
                   totalBonus += flipBonus;
                   text = `${flips > 1 ? 'DOUBLE ' : ''}FLIP!`;
                   subText = `+$${totalBonus} (Air: ${seconds}s)`;

                   if (flips > 1) {
                       soundManagerRef.current?.playDoubleFlipSound();
                   } else {
                       soundManagerRef.current?.playFlipSound();
                   }
               }

               gameStateRef.current.coins += totalBonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text, subText, id: Date.now() });
               setTimeout(() => setNotification(null), 3000);
           } else if (stuntRef.current.flips > 0) {
               // Just flips, low air time
               const bonus = stuntRef.current.flips * 1000;
               gameStateRef.current.coins += bonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text: `${stuntRef.current.flips > 1 ? 'DOUBLE ' : ''}FLIP!`, subText: `+$${bonus}`, id: Date.now() });
               setTimeout(() => setNotification(null), 2500);

               if (stuntRef.current.flips > 1) {
                   soundManagerRef.current?.playDoubleFlipSound();
               } else {
                   soundManagerRef.current?.playFlipSound();
               }
           }

           stuntRef.current = { inAir: false, startAngle: 0, flips: 0, airTime: 0 };
       }
    } else {
       if (!stuntRef.current.inAir) {
           // Takeoff
           stuntRef.current.inAir = true;
           stuntRef.current.startAngle = chassis.angle;
           stuntRef.current.flips = 0;
           stuntRef.current.airTime = 0;
       } else {
           stuntRef.current.airTime++;
           // Check rotation. Using 1.8 PI (approx 325 degrees) to be generous for a "flip"
           const diff = Math.abs(chassis.angle - stuntRef.current.startAngle);
           const currentFlips = Math.floor(diff / (Math.PI * 1.8));
           if (currentFlips > stuntRef.current.flips) {
               stuntRef.current.flips = currentFlips;
           }
       }
    }

    const applyPower = (targetSpeed: number) => {
        if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
        }
        if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
        }
    };

    if (keys.right) {
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
      }
      if (chassis.angularVelocity > -maxRotation) {
         Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
      }
      if (chassis.angularVelocity < maxRotation) {
        Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
      }
    }

    // --- RENDER ---
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // Chunk Loading
    const carX = chassis.position.x;
    if (carX > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Wall Update
    const wallTargetX = carX - CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // Particles
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity for particles
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : selectedMap.particleColor);
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);

       // Background Parallax
       if (backgroundLayerRef.current) {
           const parallaxFactor = 0.05; // Move slower than camera
           const bgX = carX * (1 - parallaxFactor);
           // We keep Y relative or fixed depending on preference, usually sky moves less
           backgroundLayerRef.current.setAttribute('transform', `translate(${carX - viewBoxX - (carX * 0.02)}, ${chassis.position.y - viewBoxY - 200})`);
       }
    }

    // HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config, selectedMap]);

  // Decoration Rendering
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           // Only show grass on earth, maybe rocks on moon?
           if (selectedMap.backgroundType === 'moon') {
               // Render small rocks/craters instead of grass
               return (
                 <g key={`rock-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                     <circle cx="0" cy="5" r={deco.scale * 5} fill={selectedMap.groundDarkColor} opacity="0.6" />
                 </g>
               )
           }

           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks, selectedMap]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={selectedMap.groundDarkColor} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks, selectedMap]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds, config.COIN_SIZE]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  const backgroundElements = useMemo(() => {
      if (selectedMap.backgroundType === 'moon') {
          return (
              <g ref={backgroundLayerRef}>
                  {stars.map((s, i) => (
                      <circle key={i} cx={s.x} cy={s.y} r={s.r} fill="white" opacity={s.opacity} />
                  ))}
                  <circle cx="800" cy="-200" r="100" fill="#2563eb" opacity="0.8" /> {/* Simple Earth */}
                  <circle cx="820" cy="-250" r="30" fill="#16a34a" opacity="0.6" /> {/* Continent */}
              </g>
          )
      }
      return <g ref={backgroundLayerRef}></g>; // Empty for earth, dynamic gradient handles it
  }, [selectedMap, stars]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-slate-900 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Sound Debug Bar */}
      <div className="absolute top-20 left-4 z-10 flex flex-col items-center gap-1">
          <div className="w-4 h-16 bg-slate-800 rounded-full overflow-hidden border border-slate-600 relative shadow-lg">
              <div 
                  ref={soundBarRef}
                  className="w-full bg-green-400 absolute bottom-0 transition-all duration-75"
                  style={{ height: '0%' }}
              />
          </div>
          <span className="text-[10px] text-slate-400 font-bold tracking-wider">VOL</span>
      </div>

      {/* Floating Notification */}
      {notification && (
          <div className="absolute top-32 left-1/2 transform -translate-x-1/2 z-40 animate-bounce flex flex-col items-center">
              <div className="text-4xl font-black text-yellow-400 drop-shadow-[0_4px_4px_rgba(0,0,0,0.5)] italic whitespace-nowrap">
                  {notification.text}
              </div>
              {notification.subText && (
                  <div className="text-xl font-bold text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.5)] mt-1">
                      {notification.subText}
                  </div>
              )}
          </div>
      )}

      {/* Debug Toggle */}
      <div className="absolute top-4 right-4 z-30">
          <button 
            onClick={() => setIsDebugOpen(!isDebugOpen)}
            className="w-10 h-10 bg-slate-800/80 backdrop-blur text-white rounded-lg border border-slate-600 flex items-center justify-center hover:bg-slate-700 transition"
          >
             ⚙️
          </button>
      </div>

      {isDebugOpen && (
          <DebugMenu 
             config={config} 
             onUpdate={onUpdateConfig} 
             onClose={() => setIsDebugOpen(false)} 
             onReset={onResetConfig}
          />
      )}

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-black/60 active:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-black/60 active:bg-emerald-900/60 shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={selectedMap.groundColor} />
                <circle cx="10" cy="10" r="2" fill={selectedMap.groundDarkColor} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={selectedMap.groundDarkColor} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={selectedMap.groundDarkColor} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={selectedMap.groundDarkColor} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        {backgroundElements}

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        <g>
            {Array.from({ length: config.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} 
                L -${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} Z`}
            fill={selectedCar.bodyColor}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

export class SoundManager {
    private static audioContext: AudioContext | null = null;
    private static masterGain: GainNode | null = null;
    private static analyser: AnalyserNode | null = null;
    private static dataArray: Uint8Array | null = null;
    private static bufferCache: Map<string, AudioBuffer> = new Map();

    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    // Continuous Sound Nodes
    private engineOsc: OscillatorNode | null = null;
    private engineGain: GainNode | null = null;

    private windSource: AudioBufferSourceNode | null = null;
    private windGain: GainNode | null = null;

    private tireSource: AudioBufferSourceNode | null = null;
    private tireGain: GainNode | null = null;

    private isInitialized: boolean = false;

    constructor() {
      // Lazy init called on first interaction usually, but we set up structure
    }

    private init() {
        if (typeof window === 'undefined') return;

        if (!SoundManager.audioContext) {
            const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
            if (AudioContextClass) {
                const ctx = new AudioContextClass();
                SoundManager.audioContext = ctx;

                // 1. Master Gain
                const masterGain = ctx.createGain();
                masterGain.gain.value = 0.25; 
                SoundManager.masterGain = masterGain;

                // 2. Analyser
                const analyser = ctx.createAnalyser();
                analyser.fftSize = 256; 
                SoundManager.analyser = analyser;
                SoundManager.dataArray = new Uint8Array(analyser.frequencyBinCount);

                masterGain.connect(analyser);
                analyser.connect(ctx.destination);

                // Create Noise Buffers once
                this.createNoiseBuffer('white', ctx);
                this.createNoiseBuffer('brown', ctx);
            }
        }

        if (SoundManager.audioContext && !this.isInitialized) {
            this.setupContinuousSounds();
            this.isInitialized = true;
        }
    }

    private createNoiseBuffer(type: 'white' | 'brown', ctx: AudioContext) {
        if (SoundManager.bufferCache.has(type)) return;

        const bufferSize = ctx.sampleRate * 2; // 2 seconds
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);

        let lastOut = 0;
        for (let i = 0; i < bufferSize; i++) {
            if (type === 'white') {
                data[i] = Math.random() * 2 - 1;
            } else {
                // Brown noise approximation
                const white = Math.random() * 2 - 1;
                data[i] = (lastOut + (0.02 * white)) / 1.02;
                lastOut = data[i];
                data[i] *= 3.5; // Compensate for gain loss
            }
        }
        SoundManager.bufferCache.set(type, buffer);
    }

    private setupContinuousSounds() {
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // --- ENGINE ---
        this.engineOsc = ctx.createOscillator();
        this.engineOsc.type = 'sawtooth';
        this.engineOsc.frequency.value = 60;

        // Engine Filter (Lowpass to muffle the harsh saw)
        const engineFilter = ctx.createBiquadFilter();
        engineFilter.type = 'lowpass';
        engineFilter.frequency.value = 400;

        this.engineGain = ctx.createGain();
        this.engineGain.gain.value = 0;

        this.engineOsc.connect(engineFilter);
        engineFilter.connect(this.engineGain);
        this.engineGain.connect(master);
        this.engineOsc.start();

        // --- WIND (In Air) ---
        const whiteBuffer = SoundManager.bufferCache.get('white');
        if (whiteBuffer) {
            this.windSource = ctx.createBufferSource();
            this.windSource.buffer = whiteBuffer;
            this.windSource.loop = true;

            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 800; // Higher freq for "air" feel

            this.windGain = ctx.createGain();
            this.windGain.gain.value = 0;

            this.windSource.connect(windFilter);
            windFilter.connect(this.windGain);
            this.windGain.connect(master);
            this.windSource.start();
        }

        // --- TIRES (On Ground) ---
        const brownBuffer = SoundManager.bufferCache.get('brown');
        if (brownBuffer) {
            this.tireSource = ctx.createBufferSource();
            this.tireSource.buffer = brownBuffer;
            this.tireSource.loop = true;

            this.tireGain = ctx.createGain();
            this.tireGain.gain.value = 0;

            this.tireSource.connect(this.tireGain);
            this.tireGain.connect(master);
            this.tireSource.start();
        }
    }

    public resume() {
      const ctx = SoundManager.audioContext;
      if (!ctx) {
          this.init();
          return;
      }
      if (ctx.state === 'suspended' || (ctx.state as string) === 'interrupted') {
        ctx.resume();
      }
      if (!this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
    }

    public updateContinuous(speedRatio: number, isGrounded: boolean, isGasPressed: boolean) {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Clamp speed ratio 0-1 (approx)
        const speed = Math.max(0, Math.min(1, Math.abs(speedRatio)));

        // --- ENGINE ---
        if (this.engineOsc && this.engineGain) {
            // Pitch: 80Hz idle -> 300Hz max
            const targetFreq = 80 + (speed * 220) + (isGasPressed ? 50 : 0);
            this.engineOsc.frequency.setTargetAtTime(targetFreq, t, 0.1);

            // Volume: Idle 0.1, Moving/Gas 0.3
            const targetGain = 0.1 + (speed * 0.1) + (isGasPressed ? 0.1 : 0);
            this.engineGain.gain.setTargetAtTime(targetGain, t, 0.1);
        }

        // --- TIRES ---
        if (this.tireGain) {
            // Only audible when grounded and moving
            const tireVol = isGrounded && speed > 0.1 ? Math.min(0.2, speed * 0.3) : 0;
            this.tireGain.gain.setTargetAtTime(tireVol, t, 0.1);
        }

        // --- WIND ---
        if (this.windGain) {
            // Reduced volume heavily
            let windVol = speed * 0.05; 
            if (!isGrounded) windVol += 0.05; // Slightly more in air, but much quieter than before
            if (speed < 0.1) windVol = 0;

            this.windGain.gain.setTargetAtTime(windVol, t, 0.2);
        }
    }

    public getAudioLevel(): number {
        if (!SoundManager.analyser || !SoundManager.dataArray) return 0;
        SoundManager.analyser.getByteTimeDomainData(SoundManager.dataArray);

        let sum = 0;
        for (let i = 0; i < SoundManager.dataArray.length; i++) {
            const amplitude = (SoundManager.dataArray[i] - 128) / 128;
            sum += amplitude * amplitude;
        }

        const rms = Math.sqrt(sum / SoundManager.dataArray.length);
        // Adjusted sensitivity
        return Math.min(1.0, rms * 10); 
    }

    public playCoinSound() {
      if (!SoundManager.audioContext) this.init();
      const ctx = SoundManager.audioContext;
      const master = SoundManager.masterGain;
      if (!ctx || !master) return;

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      // Shifted scale up one octave (x2 frequency)
      // C6 Scale
      const scale = [1046.50, 1174.66, 1318.51, 1396.91, 1567.98, 1760.00, 1975.53, 2093.00]; 
      const frequency = scale[this.coinStep % scale.length];

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine'; // Single pure wave
      osc.frequency.setValueAtTime(frequency, ctx.currentTime);

      // Simple envelope
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.02); // Faster attack
      gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

      osc.connect(gain);
      gain.connect(master);

      osc.start();
      osc.stop(ctx.currentTime + 0.35);

      this.coinStep++;
    }

    public playFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'triangle'; 
        osc.frequency.setValueAtTime(300, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.3);

        gain.gain.setValueAtTime(0.15, ctx.currentTime); 
        gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

        osc.connect(gain);
        gain.connect(master);

        osc.start();
        osc.stop(ctx.currentTime + 0.35);
    }

    public playDoubleFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // Major Third Arpeggio
        const notes = [600, 750, 900];
        const now = ctx.currentTime;

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = 'square';
            osc.frequency.value = freq;

            const start = now + (i * 0.1);
            gain.gain.setValueAtTime(0, start);
            gain.gain.linearRampToValueAtTime(0.1, start + 0.05);
            gain.gain.linearRampToValueAtTime(0, start + 0.3);

            osc.connect(gain);
            gain.connect(master);
            osc.start(start);
            osc.stop(start + 0.4);
        });
    }

    public startAirSound() {} 
    public stopAirSound() {}
}

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onResetConfig: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark';
}

interface StuntState {
    inAir: boolean;
    startAngle: number;
    flips: number;
    airTime: number;
}

const Game: React.FC<GameProps> = ({ onGameOver, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); // Count how many wheels are touching ground
  const stuntRef = useRef<StuntState>({ inAir: false, startAngle: 0, flips: 0, airTime: 0 });
  const processedCoinIds = useRef<Set<number>>(new Set());

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // UI Notification State
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);
  const backgroundLayerRef = useRef<SVGGElement>(null);

  // Sound Bar Ref
  const soundBarRef = useRef<HTMLDivElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [stars, setStars] = useState<{x: number, y: number, r: number, opacity: number}[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());

  // Generate static stars for Moon map
  useEffect(() => {
      if (selectedMap.backgroundType === 'moon') {
          const s = [];
          for(let i=0; i<100; i++) {
              s.push({
                  x: Math.random() * 2000,
                  y: Math.random() * 1000 - 500,
                  r: Math.random() * 2,
                  opacity: Math.random()
              });
          }
          setStars(s);
      } else {
          setStars([]);
      }
  }, [selectedMap]);

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      // Clouds only for Earth
      if (selectedMap.backgroundType === 'earth') {
          const newClouds = generateClouds(startX, length);
          setClouds(prev => [...prev, ...newClouds]);
      }

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config, selectedMap.backgroundType]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events for Game Logic
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            if ((isChassisA && isGroundB) || (isChassisB && isGroundA)) {
                const chassisBody = isChassisA ? bodyA : bodyB;
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;
                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedX = localX * cos - localY * sin;
                        const rotatedY = localX * sin + localY * cos;

                        if (rotatedY < -10 && Math.abs(rotatedX) < 40) {
                            gameStateRef.current.isGameOver = true;
                            // Reset engine sound on game over
                            soundManagerRef.current?.updateContinuous(0, true, false);
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Coin Logic
            let coinBody = null;
            const isCar = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);
            if (isCar(bodyA) && bodyB.label === 'coin') coinBody = bodyB;
            if (isCar(bodyB) && bodyA.label === 'coin') coinBody = bodyA;

            if (coinBody) {
                // Synchronous check to prevent double-collection in same frame
                if (processedCoinIds.current.has(coinBody.id)) continue;
                processedCoinIds.current.add(coinBody.id);

                // Deep remove is required because coins are nested in Chunk composites
                Matter.World.remove(engine.world, coinBody, true);

                soundManagerRef.current?.playCoinSound(); 
                gameStateRef.current.coins += config.COIN_VALUE;
                if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;

                // Update React state for visual removal
                setCollectedCoinIds(prev => {
                    const next = new Set(prev);
                    next.add(coinBody.id);
                    return next;
                });
            }

            // Particle Logic
            let wheelBody = null;
            if (isWheelA && isGroundB) wheelBody = bodyA;
            if (isWheelB && isGroundA) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGroundA = bodyA.label === 'ground';
            const isGroundB = bodyB.label === 'ground';

            if ((isWheelA && isGroundB) || (isWheelB && isGroundA)) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
      // Stop continuous sounds on unmount
      soundManagerRef.current?.updateContinuous(0, true, false);
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 10 - 5);
              p.y = y + (Math.random() * 10 - 5);
              p.type = type;
              p.maxLife = config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI - (Math.PI / 2);
              p.vx = Math.cos(angle) * speed * (Math.random() > 0.5 ? 1 : -1);
              p.vy = -Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Ensure Audio Context is resumed on first user interaction
  useEffect(() => {
    const handleInput = () => {
        soundManagerRef.current?.resume();
    };

    window.addEventListener('keydown', handleInput);
    window.addEventListener('mousedown', handleInput);
    window.addEventListener('touchstart', handleInput);

    return () => {
        window.removeEventListener('keydown', handleInput);
        window.removeEventListener('mousedown', handleInput);
        window.removeEventListener('touchstart', handleInput);
    };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // Update Sound Bar
    if (soundManagerRef.current && soundBarRef.current) {
        const level = soundManagerRef.current.getAudioLevel();
        const height = Math.min(100, level * 300); 
        soundBarRef.current.style.height = `${height}%`;
        soundBarRef.current.style.opacity = height > 2 ? '1' : '0.3';
    }

    const CONFIG = config;

    // Day/Night Cycle
    if (selectedMap.backgroundType === 'earth') {
        gameTimeRef.current = (gameTimeRef.current + 1) % CONFIG.DAY_CYCLE_FRAMES;
        const cyclePos = gameTimeRef.current / CONFIG.DAY_CYCLE_FRAMES;

        let skyTop = selectedMap.skyColorStart;
        let skyBot = selectedMap.skyColorEnd;

        if (cyclePos > 0.4 && cyclePos <= 0.5) {
            const t = (cyclePos - 0.4) * 10;
            skyTop = interpolateColor(selectedMap.skyColorStart, COLORS.skyNightStart, t);
            skyBot = interpolateColor(selectedMap.skyColorEnd, COLORS.skyNightEnd, t);
        } else if (cyclePos > 0.5 && cyclePos <= 0.9) {
            skyTop = COLORS.skyNightStart;
            skyBot = COLORS.skyNightEnd;
        } else if (cyclePos > 0.9) {
            const t = (cyclePos - 0.9) * 10;
            skyTop = interpolateColor(COLORS.skyNightStart, selectedMap.skyColorStart, t);
            skyBot = interpolateColor(COLORS.skyNightEnd, selectedMap.skyColorEnd, t);
        }

        isNightRef.current = (cyclePos > 0.45 && cyclePos < 0.95);

        if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${skyTop}, ${skyBot})`;
        }
    } else {
        // Static background for Moon
         if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})`;
        }
    }

    Matter.Engine.update(engine, 1000 / 60);

    // --- CAR PHYSICS LOGIC ---
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = selectedCar.speed; 
    const acceleration = selectedCar.acceleration;

    const isGrounded = wheelGroundContacts.current > 0;

    // --- AUDIO UPDATE ---
    if (soundManagerRef.current && chassis) {
        // Calculate approx speed ratio for audio
        // Typical max angular velocity is around 1.0 - 2.0 rad/s in Physics config
        // Body velocity is roughly related.
        const speed = Matter.Vector.magnitude(chassis.velocity);
        const speedRatio = Math.min(1.5, speed / 25); // Normalize approx

        soundManagerRef.current.updateContinuous(
            speedRatio, 
            isGrounded, 
            keys.right
        );
    }

    const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
    const maxRotation = CONFIG.MAX_ROTATION_SPEED;
    const brakeRotationFactor = 0.5;

    // Stunt & Air Time Logic
    if (isGrounded) {
       // Just landed?
       if (stuntRef.current.inAir) {

           // Check Air Time Bonus
           // 60 frames = 1 second. Give bonus if > 1s
           if (stuntRef.current.airTime > 60) {
               const seconds = (stuntRef.current.airTime / 60).toFixed(1);
               const airBonus = Math.floor(stuntRef.current.airTime * 50); // Points per frame

               // Combine with flip bonus if any
               const flips = stuntRef.current.flips;
               let totalBonus = airBonus;
               let text = `AIR TIME ${seconds}s`;
               let subText = `+$${airBonus}`;

               if (flips > 0) {
                   const flipBonus = flips * 1000;
                   totalBonus += flipBonus;
                   text = `${flips > 1 ? 'DOUBLE ' : ''}FLIP!`;
                   subText = `+$${totalBonus} (Air: ${seconds}s)`;

                   if (flips > 1) {
                       soundManagerRef.current?.playDoubleFlipSound();
                   } else {
                       soundManagerRef.current?.playFlipSound();
                   }
               }

               gameStateRef.current.coins += totalBonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text, subText, id: Date.now() });
               setTimeout(() => setNotification(null), 3000);
           } else if (stuntRef.current.flips > 0) {
               // Just flips, low air time
               const bonus = stuntRef.current.flips * 1000;
               gameStateRef.current.coins += bonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text: `${stuntRef.current.flips > 1 ? 'DOUBLE ' : ''}FLIP!`, subText: `+$${bonus}`, id: Date.now() });
               setTimeout(() => setNotification(null), 2500);

               if (stuntRef.current.flips > 1) {
                   soundManagerRef.current?.playDoubleFlipSound();
               } else {
                   soundManagerRef.current?.playFlipSound();
               }
           }

           stuntRef.current = { inAir: false, startAngle: 0, flips: 0, airTime: 0 };
       }
    } else {
       if (!stuntRef.current.inAir) {
           // Takeoff
           stuntRef.current.inAir = true;
           stuntRef.current.startAngle = chassis.angle;
           stuntRef.current.flips = 0;
           stuntRef.current.airTime = 0;
       } else {
           stuntRef.current.airTime++;
           // Check rotation. Using 1.8 PI (approx 325 degrees) to be generous for a "flip"
           const diff = Math.abs(chassis.angle - stuntRef.current.startAngle);
           const currentFlips = Math.floor(diff / (Math.PI * 1.8));
           if (currentFlips > stuntRef.current.flips) {
               stuntRef.current.flips = currentFlips;
           }
       }
    }

    const applyPower = (targetSpeed: number) => {
        if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
        }
        if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
        }
    };

    if (keys.right) {
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
      }
      if (chassis.angularVelocity > -maxRotation) {
         Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
      }
      if (chassis.angularVelocity < maxRotation) {
        Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
      }
    }

    // --- RENDER ---
    if (chassisDomRef.current && wheelBackDomRef.current && wheelFrontDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current.setAttribute('cx', wbPos.x.toString());
        wheelBackDomRef.current.setAttribute('cy', wbPos.y.toString());
        if (wheelBackSpokesRef.current) {
            wheelBackSpokesRef.current.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);
        }

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current.setAttribute('cx', wfPos.x.toString());
        wheelFrontDomRef.current.setAttribute('cy', wfPos.y.toString());
        if (wheelFrontSpokesRef.current) {
            wheelFrontSpokesRef.current.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
        }
    }

    // Chunk Loading
    const carX = chassis.position.x;
    if (carX > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Wall Update
    const wallTargetX = carX - CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // Particles
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += 0.2; // Gravity for particles
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                el.setAttribute('fill', p.type === 'spark' ? COLORS.particleSpark : selectedMap.particleColor);
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                el.setAttribute('r', (p.type === 'spark' ? 2 : 4).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };

       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);

       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);

       // Background Parallax
       if (backgroundLayerRef.current) {
           const parallaxFactor = 0.05; // Move slower than camera
           const bgX = carX * (1 - parallaxFactor);
           // We keep Y relative or fixed depending on preference, usually sky moves less
           backgroundLayerRef.current.setAttribute('transform', `translate(${carX - viewBoxX - (carX * 0.02)}, ${chassis.position.y - viewBoxY - 200})`);
       }
    }

    // HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config, selectedMap]);

  // Decoration Rendering
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);

           if (deco.type === 3) {
             // Lamp Post
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }

           // Only show grass on earth, maybe rocks on moon?
           if (selectedMap.backgroundType === 'moon') {
               // Render small rocks/craters instead of grass
               return (
                 <g key={`rock-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                     <circle cx="0" cy="5" r={deco.scale * 5} fill={selectedMap.groundDarkColor} opacity="0.6" />
                 </g>
               )
           }

           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks, selectedMap]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={selectedMap.groundDarkColor} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks, selectedMap]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
                      <text y="5" textAnchor="middle" fontSize="14" fontWeight="bold" fill="#B45309">$</text>
                      <circle cx="-4" cy="-4" r="3" fill="white" opacity="0.5" />
                  </g>
              );
          })
      );
  }, [chunks, collectedCoinIds, config.COIN_SIZE]);

  const cloudElements = useMemo(() => {
      return clouds.map((cloud, i) => (
          <g key={`cloud-${i}`} transform={`translate(${cloud.x}, ${cloud.y}) scale(${cloud.scale})`}>
              <path 
                d="M 25,60 Q 40,30 70,50 Q 90,20 120,50 Q 150,30 170,60 Q 190,60 190,80 Q 190,110 160,110 L 40,110 Q 10,110 10,80 Q 10,60 25,60 Z" 
                fill="white" 
                opacity="0.6"
              />
          </g>
      ));
  }, [clouds]);

  const backgroundElements = useMemo(() => {
      if (selectedMap.backgroundType === 'moon') {
          return (
              <g ref={backgroundLayerRef}>
                  {stars.map((s, i) => (
                      <circle key={i} cx={s.x} cy={s.y} r={s.r} fill="white" opacity={s.opacity} />
                  ))}
                  <circle cx="800" cy="-200" r="100" fill="#2563eb" opacity="0.8" /> {/* Simple Earth */}
                  <circle cx="820" cy="-250" r="30" fill="#16a34a" opacity="0.6" /> {/* Continent */}
              </g>
          )
      }
      return <g ref={backgroundLayerRef}></g>; // Empty for earth, dynamic gradient handles it
  }, [selectedMap, stars]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-slate-900 overflow-hidden cursor-none select-none transition-colors duration-1000">

      {/* HUD Layer */}
      <div className="absolute top-4 left-4 z-10 pointer-events-none flex gap-4">
        <div className="bg-slate-900/80 backdrop-blur text-white px-4 py-2 rounded-lg border border-slate-700 shadow-lg">
           <div className="text-xs text-slate-400 uppercase font-bold">Distance</div>
           <div ref={hudDistanceRef} className="text-2xl font-mono font-bold">0 m</div>
        </div>
        <div className="bg-slate-900/80 backdrop-blur text-yellow-400 px-4 py-2 rounded-lg border border-yellow-700/50 shadow-lg">
           <div className="text-xs text-yellow-600 uppercase font-bold">Coins</div>
           <div ref={hudCoinsRef} className="text-2xl font-mono font-bold">$ 0</div>
        </div>
      </div>

      {/* Sound Debug Bar */}
      <div className="absolute top-20 left-4 z-10 flex flex-col items-center gap-1">
          <div className="w-4 h-16 bg-slate-800 rounded-full overflow-hidden border border-slate-600 relative shadow-lg">
              <div 
                  ref={soundBarRef}
                  className="w-full bg-green-400 absolute bottom-0 transition-all duration-75"
                  style={{ height: '0%' }}
              />
          </div>
          <span className="text-[10px] text-slate-400 font-bold tracking-wider">VOL</span>
      </div>

      {/* Floating Notification */}
      {notification && (
          <div className="absolute top-32 left-1/2 transform -translate-x-1/2 z-40 animate-bounce flex flex-col items-center">
              <div className="text-4xl font-black text-yellow-400 drop-shadow-[0_4px_4px_rgba(0,0,0,0.5)] italic whitespace-nowrap">
                  {notification.text}
              </div>
              {notification.subText && (
                  <div className="text-xl font-bold text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.5)] mt-1">
                      {notification.subText}
                  </div>
              )}
          </div>
      )}

      {/* Debug Toggle */}
      <div className="absolute top-4 right-4 z-30">
          <button 
            onClick={() => setIsDebugOpen(!isDebugOpen)}
            className="w-10 h-10 bg-slate-800/80 backdrop-blur text-white rounded-lg border border-slate-600 flex items-center justify-center hover:bg-slate-700 transition"
          >
             ⚙️
          </button>
      </div>

      {isDebugOpen && (
          <DebugMenu 
             config={config} 
             onUpdate={onUpdateConfig} 
             onClose={() => setIsDebugOpen(false)} 
             onReset={onResetConfig}
          />
      )}

      {/* Controls */}
      <div className="absolute bottom-8 left-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-red-500 bg-black/60 active:bg-red-900/60 shadow-[0_0_15px_rgba(239,68,68,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.left = false}
           onMouseLeave={() => gameStateRef.current.keys.left = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.left = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.left = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-red-100 mb-1">◀</span>
               <span className="text-[10px] font-bold text-red-200 uppercase tracking-widest">Brake</span>
            </div>
         </button>
      </div>

      <div className="absolute bottom-8 right-8 z-30 flex items-center justify-center">
         <button
           className="w-24 h-24 rounded-full border-4 border-emerald-500 bg-black/60 active:bg-emerald-900/60 shadow-[0_0_15px_rgba(16,185,129,0.4)] transition-all transform active:scale-95 flex items-center justify-center"
           onMouseDown={() => { gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onMouseUp={() => gameStateRef.current.keys.right = false}
           onMouseLeave={() => gameStateRef.current.keys.right = false}
           onTouchStart={(e) => { e.preventDefault(); gameStateRef.current.keys.right = true; soundManagerRef.current?.resume(); }}
           onTouchEnd={(e) => { e.preventDefault(); gameStateRef.current.keys.right = false; }}
         >
            <div className="flex flex-col items-center">
               <span className="text-3xl text-emerald-100 mb-1">▶</span>
               <span className="text-[10px] font-bold text-emerald-200 uppercase tracking-widest">Gas</span>
            </div>
         </button>
      </div>

      {/* Game World */}
      <svg 
        ref={svgRef}
        className="w-full h-full"
        preserveAspectRatio="xMidYMid slice"
        xmlns="http://www.w3.org/2000/svg"
      >
        <defs>
            <pattern id="groundPattern" patternUnits="userSpaceOnUse" width="40" height="40" patternTransform="rotate(45)">
                <rect width="100%" height="100%" fill={selectedMap.groundColor} />
                <circle cx="10" cy="10" r="2" fill={selectedMap.groundDarkColor} opacity="0.3" />
                <circle cx="30" cy="30" r="3" fill={selectedMap.groundDarkColor} opacity="0.2" />
                <circle cx="15" cy="35" r="1.5" fill={selectedMap.groundDarkColor} opacity="0.4" />
                <circle cx="35" cy="5" r="2" fill={selectedMap.groundDarkColor} opacity="0.2" />
            </pattern>
            {/* Lamp Glow */}
            <radialGradient id="lampGlowGradient">
                <stop offset="0%" stopColor={COLORS.lampLight} stopOpacity="0.8" />
                <stop offset="50%" stopColor={COLORS.lampGlow} stopOpacity="0.3" />
                <stop offset="100%" stopColor={COLORS.lampGlow} stopOpacity="0" />
            </radialGradient>
        </defs>

        {backgroundElements}

        <g ref={cloudsLayerRef}>
            {cloudElements}
        </g>

        <g>
            {terrainPaths}
            {decorationsElements}
            {coinElements}
        </g>

        <g>
            {Array.from({ length: config.PARTICLE_POOL_SIZE }).map((_, i) => (
                <circle 
                    key={`p-${i}`} 
                    ref={el => { particleDomRefs.current[i] = el; }} 
                    r="0" 
                    visibility="hidden" 
                />
            ))}
        </g>

        {/* Car */}
        <path
            ref={chassisDomRef}
            d={`M -${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} -${config.CAR_HEIGHT/2} 
                L ${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} 
                L -${config.CAR_WIDTH/2} ${config.CAR_HEIGHT/2} Z`}
            fill={selectedCar.bodyColor}
            stroke="rgba(0,0,0,0.5)"
            strokeWidth="2"
        />

        <circle ref={wheelBackDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

        <circle ref={wheelFrontDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelFrontSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
             <line x1="0" y1={-config.WHEEL_SIZE} x2="0" y2={config.WHEEL_SIZE} stroke={COLORS.carRim} strokeWidth="4" />
        </g>

      </svg>

    </div>
  );
};

export default Game;

export class SoundManager {
    private static audioContext: AudioContext | null = null;
    private static masterGain: GainNode | null = null;
    private static analyser: AnalyserNode | null = null;
    private static dataArray: Uint8Array | null = null;
    private static bufferCache: Map<string, AudioBuffer> = new Map();

    private coinStep: number = 0;
    private lastCoinTime: number = 0;

    // Continuous Sound Nodes
    private engineOsc: OscillatorNode | null = null;
    private engineGain: GainNode | null = null;

    private windSource: AudioBufferSourceNode | null = null;
    private windGain: GainNode | null = null;

    private tireSource: AudioBufferSourceNode | null = null;
    private tireGain: GainNode | null = null;

    private isInitialized: boolean = false;

    constructor() {
      // Lazy init called on first interaction usually, but we set up structure
    }

    private init() {
        if (typeof window === 'undefined') return;

        if (!SoundManager.audioContext) {
            const AudioContextClass = (window.AudioContext || (window as any).webkitAudioContext);
            if (AudioContextClass) {
                const ctx = new AudioContextClass();
                SoundManager.audioContext = ctx;

                // 1. Master Gain
                const masterGain = ctx.createGain();
                masterGain.gain.value = 0.25; 
                SoundManager.masterGain = masterGain;

                // 2. Analyser
                const analyser = ctx.createAnalyser();
                analyser.fftSize = 256; 
                SoundManager.analyser = analyser;
                SoundManager.dataArray = new Uint8Array(analyser.frequencyBinCount);

                masterGain.connect(analyser);
                analyser.connect(ctx.destination);

                // Create Noise Buffers once
                this.createNoiseBuffer('white', ctx);
                this.createNoiseBuffer('brown', ctx);
            }
        }

        if (SoundManager.audioContext && !this.isInitialized) {
            this.setupContinuousSounds();
            this.isInitialized = true;
        }
    }

    private createNoiseBuffer(type: 'white' | 'brown', ctx: AudioContext) {
        if (SoundManager.bufferCache.has(type)) return;

        const bufferSize = ctx.sampleRate * 2; // 2 seconds
        const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
        const data = buffer.getChannelData(0);

        let lastOut = 0;
        for (let i = 0; i < bufferSize; i++) {
            if (type === 'white') {
                data[i] = Math.random() * 2 - 1;
            } else {
                // Brown noise approximation
                const white = Math.random() * 2 - 1;
                data[i] = (lastOut + (0.02 * white)) / 1.02;
                lastOut = data[i];
                data[i] *= 3.5; // Compensate for gain loss
            }
        }
        SoundManager.bufferCache.set(type, buffer);
    }

    private setupContinuousSounds() {
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // --- ENGINE ---
        this.engineOsc = ctx.createOscillator();
        this.engineOsc.type = 'sawtooth';
        this.engineOsc.frequency.value = 60;

        // Engine Filter (Lowpass to muffle the harsh saw)
        const engineFilter = ctx.createBiquadFilter();
        engineFilter.type = 'lowpass';
        engineFilter.frequency.value = 400;

        this.engineGain = ctx.createGain();
        this.engineGain.gain.value = 0;

        this.engineOsc.connect(engineFilter);
        engineFilter.connect(this.engineGain);
        this.engineGain.connect(master);
        this.engineOsc.start();

        // --- WIND (In Air) ---
        const whiteBuffer = SoundManager.bufferCache.get('white');
        if (whiteBuffer) {
            this.windSource = ctx.createBufferSource();
            this.windSource.buffer = whiteBuffer;
            this.windSource.loop = true;

            const windFilter = ctx.createBiquadFilter();
            windFilter.type = 'bandpass';
            windFilter.frequency.value = 800; // Higher freq for "air" feel

            this.windGain = ctx.createGain();
            this.windGain.gain.value = 0;

            this.windSource.connect(windFilter);
            windFilter.connect(this.windGain);
            this.windGain.connect(master);
            this.windSource.start();
        }

        // --- TIRES (On Ground) ---
        const brownBuffer = SoundManager.bufferCache.get('brown');
        if (brownBuffer) {
            this.tireSource = ctx.createBufferSource();
            this.tireSource.buffer = brownBuffer;
            this.tireSource.loop = true;

            this.tireGain = ctx.createGain();
            this.tireGain.gain.value = 0;

            this.tireSource.connect(this.tireGain);
            this.tireGain.connect(master);
            this.tireSource.start();
        }
    }

    public resume() {
      const ctx = SoundManager.audioContext;
      if (!ctx) {
          this.init();
          return;
      }
      if (ctx.state === 'suspended' || (ctx.state as string) === 'interrupted') {
        ctx.resume();
      }
      if (!this.isInitialized) {
          this.setupContinuousSounds();
          this.isInitialized = true;
      }
    }

    public updateContinuous(speedRatio: number, isGrounded: boolean, isGasPressed: boolean) {
        const ctx = SoundManager.audioContext;
        if (!ctx || !this.isInitialized) return;
        const t = ctx.currentTime;

        // Clamp speed ratio 0-1 (approx)
        const speed = Math.max(0, Math.min(1, Math.abs(speedRatio)));

        // --- ENGINE ---
        if (this.engineOsc && this.engineGain) {
            // Pitch: 80Hz idle -> 300Hz max
            const targetFreq = 80 + (speed * 220) + (isGasPressed ? 50 : 0);
            this.engineOsc.frequency.setTargetAtTime(targetFreq, t, 0.1);

            // Volume: Idle 0.1, Moving/Gas 0.3
            const targetGain = 0.1 + (speed * 0.1) + (isGasPressed ? 0.1 : 0);
            this.engineGain.gain.setTargetAtTime(targetGain, t, 0.1);
        }

        // --- TIRES ---
        if (this.tireGain) {
            // Only audible when grounded and moving
            const tireVol = isGrounded && speed > 0.1 ? Math.min(0.2, speed * 0.3) : 0;
            this.tireGain.gain.setTargetAtTime(tireVol, t, 0.1);
        }

        // --- WIND ---
        if (this.windGain) {
            // Reduced volume heavily
            let windVol = speed * 0.05; 
            if (!isGrounded) windVol += 0.05; // Slightly more in air, but much quieter than before
            if (speed < 0.1) windVol = 0;

            this.windGain.gain.setTargetAtTime(windVol, t, 0.2);
        }
    }

    public getAudioLevel(): number {
        if (!SoundManager.analyser || !SoundManager.dataArray) return 0;
        SoundManager.analyser.getByteTimeDomainData(SoundManager.dataArray);

        let sum = 0;
        for (let i = 0; i < SoundManager.dataArray.length; i++) {
            const amplitude = (SoundManager.dataArray[i] - 128) / 128;
            sum += amplitude * amplitude;
        }

        const rms = Math.sqrt(sum / SoundManager.dataArray.length);
        // Adjusted sensitivity
        return Math.min(1.0, rms * 10); 
    }

    public playCoinSound() {
      if (!SoundManager.audioContext) this.init();
      const ctx = SoundManager.audioContext;
      const master = SoundManager.masterGain;
      if (!ctx || !master) return;

      const now = Date.now();
      if (now - this.lastCoinTime > 2000) {
        this.coinStep = 0;
      }
      this.lastCoinTime = now;

      // Shifted scale up another octave (C7)
      const scale = [2093.00, 2349.32, 2637.02, 2793.83, 3135.96, 3520.00, 3951.07, 4186.01]; 
      const frequency = scale[this.coinStep % scale.length];

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine'; // Single pure wave
      osc.frequency.setValueAtTime(frequency, ctx.currentTime);

      // Simple envelope
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.02); // Faster attack
      gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

      osc.connect(gain);
      gain.connect(master);

      osc.start();
      osc.stop(ctx.currentTime + 0.35);

      this.coinStep++;
    }

    public playFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'triangle'; 
        osc.frequency.setValueAtTime(300, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(600, ctx.currentTime + 0.3);

        gain.gain.setValueAtTime(0.15, ctx.currentTime); 
        gain.gain.linearRampToValueAtTime(0.01, ctx.currentTime + 0.3);

        osc.connect(gain);
        gain.connect(master);

        osc.start();
        osc.stop(ctx.currentTime + 0.35);
    }

    public playDoubleFlipSound() {
        if (!SoundManager.audioContext) this.init();
        const ctx = SoundManager.audioContext;
        const master = SoundManager.masterGain;
        if (!ctx || !master) return;

        // Major Third Arpeggio
        const notes = [600, 750, 900];
        const now = ctx.currentTime;

        notes.forEach((freq, i) => {
            const osc = ctx.createOscillator();
            const gain = ctx.createGain();

            osc.type = 'square';
            osc.frequency.value = freq;

            const start = now + (i * 0.1);
            gain.gain.setValueAtTime(0, start);
            gain.gain.linearRampToValueAtTime(0.1, start + 0.05);
            gain.gain.linearRampToValueAtTime(0, start + 0.3);

            osc.connect(gain);
            gain.connect(master);
            osc.start(start);
            osc.stop(start + 0.4);
        });
    }

    public startAirSound() {} 
    public stopAirSound() {}
}

