import { GameConfig, CarModel } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  waterBodies: any[];
  bombBodies: any[];
  islandBodies: any[];
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = gameConfig;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.3; 
  const suspensionDamping = 0.2;   
  const suspensionLength = 9;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    if (mapType === 'mystical') {
        // Mystical Logic: Jagged cliffs, cracks, and plateaus
        const nx = globalIndex * 0.05; // Low frequency base
        const sine = Math.sin(nx);

        let h = 0;

        // Create Cliffs/Plateaus using thresholds
        if (sine > 0.5) h = 300;
        else if (sine < -0.5) h = -300;
        else h = sine * 200;

        // Add cracks (sudden dips)
        const crackNoise = Math.sin(globalIndex * 0.4);
        if (Math.abs(crackNoise) > 0.95) {
            h += 300; // Drop down (y is inverted in this calc logic usually, but here + is down in screen coords often, but context matters. Let's assume + is up in generation, inverted later. Actually dy logic flips it. )
        }

        // Add jagged noise on top
        const jagged = Math.sin(globalIndex * 0.8) * 40;

        return (h + jagged) * config.TERRAIN_AMP_1 * 0.5; // Scale down slightly to fit screen
    }

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const waterBodies: any[] = [];
  const bombBodies: any[] = [];
  const islandBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;

    const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
    const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.6; 
    const isDip = dy > 20; // Going down steep
    const isRise = dy < -20; // Going up steep
    const isValley = !isDip && !isRise && isFlatEnough; // Roughly bottom

    // --- Mystical Map Features ---
    if (mapType === 'mystical') {
        // 1. Water Pools in valleys
        // If we are somewhat flat and low relative to prev, maybe spawn water
        if (Math.random() < 0.1 && isValley) {
            // Check if we didn't just spawn water
            const poolWidth = 200;
            const poolHeight = 40;
            const wx = currentX + poolWidth/2;
            const wy = currentY - poolHeight/2;

            const water = Matter.Bodies.rectangle(wx, wy, poolWidth, poolHeight, {
                isSensor: true,
                isStatic: true,
                label: 'water',
                render: { visible: false }
            });
            waterBodies.push(water);
        }

        // 2. Hidden Bombs (Mines)
        // Spawn on flat ground occasionally
        if (Math.random() < 0.05 && isFlatEnough) {
             const bx = currentX;
             const by = currentY + 5; // Slightly buried
             const bomb = Matter.Bodies.circle(bx, by, 10, {
                 isSensor: true,
                 isStatic: true,
                 label: 'bomb',
                 render: { visible: false }
             });
             bombBodies.push(bomb);
        }

        // 3. Floating Islands
        // Spawn randomly in the air
        if (Math.random() < 0.08) {
            const ix = currentX;
            const iy = currentY - 250 - (Math.random() * 200); // High up
            const width = 150 + Math.random() * 150;
            const height = 40;

            const island = Matter.Bodies.rectangle(ix, iy, width, height, {
                isStatic: true,
                friction: 1.0,
                label: 'ground', // Treat as ground for driving
                render: { visible: false },
                chamfer: { radius: 10 }
            });
            islandBodies.push(island);
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) // Types 0, 1, 2 are grass
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    // Same logic as before
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies, ...fuelBodies, ...waterBodies, ...bombBodies, ...islandBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      waterBodies,
      bombBodies,
      islandBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

