import { GameConfig, CarModel } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  waterBodies: any[];
  bombBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  const { CAR_WIDTH, CAR_HEIGHT, WHEEL_SIZE } = gameConfig;
  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.3; 
  const suspensionDamping = 0.2;   
  const suspensionLength = 9;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    if (mapType === 'mystical') {
        // Mystical Logic: Gently rolling flat cave floor
        const nx = globalIndex * 0.02; 
        const h = Math.sin(nx) * 50; // Very gentle large waves

        const jagged = Math.sin(globalIndex * 0.5) * 10; // Slight roughness

        return (h + jagged) * config.TERRAIN_AMP_1; 
    }

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const waterBodies: any[] = [];
  const bombBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  // Track previous segments to ensure we don't spam hazards
  let segmentsSinceWater = 0;
  let segmentsSinceIsland = 0;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;
    segmentsSinceWater++;
    segmentsSinceIsland++;

    const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
    const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    const isVeryFlat = slopeFactor > 0.95;   

    // --- Mystical Map Features ---
    if (mapType === 'mystical') {
        // 1. Water Pools - Rare, only on flat
        if (Math.random() < 0.1 && isVeryFlat && segmentsSinceWater > 30) {
            const poolWidth = 240;
            const poolHeight = 50;
            const wx = currentX + poolWidth/2;
            const wy = currentY - 15; 

            const water = Matter.Bodies.rectangle(wx, wy, poolWidth, poolHeight, {
                isSensor: true,
                isStatic: true,
                label: 'water',
                render: { visible: false }
            });
            waterBodies.push(water);
            segmentsSinceWater = 0;
        }

        // 2. Hidden Bombs (Mines) - Frequent enough to be dangerous
        if (Math.random() < 0.08 && isFlatEnough) {
             const bx = currentX;
             const by = currentY + 5; 
             const bomb = Matter.Bodies.circle(bx, by, 10, {
                 isSensor: true,
                 isStatic: true,
                 label: 'bomb',
                 render: { visible: false }
             });
             bombBodies.push(bomb);
        }

        // 3. MASSIVE FLOATING ISLANDS
        if (Math.random() < 0.15 && segmentsSinceIsland > 40) {
            const width = 600 + Math.random() * 800; // Huge islands
            const ix = currentX + width / 2;
            const iy = currentY - 350 - (Math.random() * 150); // High ceiling

            const vertices = [];
            const steps = 10;
            const stepW = width / steps;

            for(let j=0; j<=steps; j++) {
                vertices.push({ x: -width/2 + j*stepW, y: (Math.random() * 10) - 5 });
            }
            for(let j=steps; j>=0; j--) {
                const jaggedY = 60 + Math.random() * 80; 
                vertices.push({ x: -width/2 + j*stepW, y: jaggedY });
            }

            const island = Matter.Bodies.fromVertices(ix, iy, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground', 
                render: { visible: false },
                chamfer: { radius: 5 }
            });

            if (island) {
                islandBodies.push(island);
                segmentsSinceIsland = 0;

                if (Math.random() < 0.5) {
                    const coin = Matter.Bodies.circle(ix, iy - 60, COIN_SIZE, {
                        isSensor: true,
                        isStatic: true,
                        label: 'coin',
                        render: { visible: false }
                    });
                    coinBodies.push(coin);
                }
            }
        }

        // 4. JUMP RAMPS
        if (Math.random() < 0.15 && isFlatEnough && segmentsSinceIsland > 5 && segmentsSinceWater > 5) {
            const rampWidth = 250 + Math.random() * 100;
            const rampHeight = 120 + Math.random() * 50;

            // Vertices for a wedge (Right Triangle) pointing UP-RIGHT
            const vertices = [
                { x: 0, y: rampHeight },        // Bottom Left
                { x: rampWidth, y: rampHeight }, // Bottom Right
                { x: rampWidth, y: 0 }           // Top Right
            ];

            const rampX = currentX + rampWidth / 2;
            const rampY = currentY - rampHeight / 2;

            const ramp = Matter.Bodies.fromVertices(rampX, rampY, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground',
                render: { visible: false }
            });

            if (ramp) {
                // Align bottom of ramp with ground
                const bounds = ramp.bounds;
                const bottomY = bounds.max.y;
                const diff = currentY - bottomY;
                Matter.Body.setPosition(ramp, { x: ramp.position.x, y: ramp.position.y + diff + 5 }); // +5 to bury slightly

                rampBodies.push(ramp);
                // Skip ahead X so we don't spawn stuff inside the ramp
                // Note: The loop controls X, we can't easily skip i without breaking path continuity visual
                // But since ramp is on top, it's fine.
            }
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies, ...fuelBodies, ...waterBodies, ...bombBodies, ...islandBodies, ...rampBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      waterBodies,
      bombBodies,
      islandBodies,
      rampBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import React, { useEffect, useRef, useState, useCallback, useMemo } from 'react';
import { COLORS } from '../constants';
import { GameConfig, CarModel, MapConfig } from '../types';
import { createEngine, createCar, generateTerrainChunk, generateClouds, createWall, Decoration, Cloud, TerrainChunk } from '../utils/physics';
import { SoundManager } from '../utils/audio';
import DebugMenu from './DebugMenu';

// We need to access Matter globally or import if available. 
const Matter = (window as any).Matter;

interface GameProps {
  onGameOver: (distance: number, coins: number) => void;
  selectedCar: CarModel;
  selectedMap: MapConfig;
  config: GameConfig;
  onUpdateConfig: (key: keyof GameConfig, value: number) => void;
  onResetConfig: () => void;
}

interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    active: boolean;
    type: 'dust' | 'spark' | 'explosion';
}

interface StuntState {
    inAir: boolean;
    startAngle: number;
    flips: number;
    airTime: number;
}

const Game: React.FC<GameProps> = ({ onGameOver, selectedCar, selectedMap, config, onUpdateConfig, onResetConfig }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const svgRef = useRef<SVGSVGElement>(null);
  const requestRef = useRef<number | null>(null);
  const engineRef = useRef<any>(null);
  const carRef = useRef<any>(null);
  const wallRef = useRef<any>(null);
  const soundManagerRef = useRef<SoundManager | null>(null);

  // Physics State
  const wheelGroundContacts = useRef(0); 
  const stuntRef = useRef<StuntState>({ inAir: false, startAngle: 0, flips: 0, airTime: 0 });
  const processedBodyIds = useRef<Set<number>>(new Set());
  const fuelRef = useRef(config.MAX_FUEL);
  const isInWaterRef = useRef(false); // Track if car is in water

  // Debug State
  const [isDebugOpen, setIsDebugOpen] = useState(false);

  // UI Notification State
  const [notification, setNotification] = useState<{text: string, subText?: string, id: number} | null>(null);

  // Day/Night Cycle
  const gameTimeRef = useRef(0);
  const isNightRef = useRef(false);

  // Chunking State
  const [chunks, setChunks] = useState<TerrainChunk[]>([]);
  const lastChunkDataRef = useRef({ endX: 0, endY: 0, globalIndex: 0, segmentsSinceFuel: 0 });
  const loadedChunksRef = useRef<any[]>([]); 

  // Camera state
  const cameraZoomRef = useRef(1.0);
  const cameraPosRef = useRef({ x: 0, y: 0 }); 

  // Refs for direct DOM manipulation
  const chassisDomRef = useRef<SVGPathElement>(null);
  const wheelBackDomRef = useRef<SVGCircleElement>(null);
  const wheelFrontDomRef = useRef<SVGCircleElement>(null);
  const wheelBackSpokesRef = useRef<SVGGElement>(null);
  const wheelFrontSpokesRef = useRef<SVGGElement>(null);
  const hudDistanceRef = useRef<HTMLDivElement>(null);
  const hudCoinsRef = useRef<HTMLDivElement>(null);
  const hudFuelBarRef = useRef<HTMLDivElement>(null);
  const wallDomRef = useRef<SVGRectElement>(null);
  const cloudsLayerRef = useRef<SVGGElement>(null);
  const backgroundLayerRef = useRef<SVGGElement>(null);
  const soundBarRef = useRef<HTMLDivElement>(null);

  // Particle System Refs
  const particlesRef = useRef<Particle[]>([]);
  const particleDomRefs = useRef<(SVGCircleElement | null)[]>([]);

  // Game state
  const gameStateRef = useRef({
    distance: 0,
    coins: 0,
    isGameOver: false,
    keys: { left: false, right: false }
  });

  // Static Data
  const [clouds, setClouds] = useState<Cloud[]>([]);
  const [stars, setStars] = useState<{x: number, y: number, r: number, opacity: number}[]>([]);
  const [collectedCoinIds, setCollectedCoinIds] = useState<Set<number>>(new Set());
  const [collectedFuelIds, setCollectedFuelIds] = useState<Set<number>>(new Set());
  const [triggeredBombIds, setTriggeredBombIds] = useState<Set<number>>(new Set());

  // Generate static stars for Moon/Mystical
  useEffect(() => {
      if (selectedMap.backgroundType === 'moon' || selectedMap.backgroundType === 'mystical') {
          const s = [];
          for(let i=0; i<150; i++) {
              s.push({
                  x: Math.random() * 2000,
                  y: Math.random() * 1000 - 500,
                  r: Math.random() * 2,
                  opacity: Math.random()
              });
          }
          setStars(s);
      } else {
          setStars([]);
      }
  }, [selectedMap]);

  // Helper to generate a chunk
  const addChunk = useCallback((startX: number) => {
      const { endY, globalIndex, segmentsSinceFuel } = lastChunkDataRef.current;
      const length = config.CHUNK_SIZE;
      const chunkId = Math.floor(startX / length);

      const newChunk = generateTerrainChunk(
          chunkId, 
          startX, 
          endY, 
          globalIndex, 
          length, 
          isNightRef.current,
          config,
          selectedMap.backgroundType,
          segmentsSinceFuel
      );

      if (engineRef.current) {
        Matter.World.add(engineRef.current.world, newChunk.composite);
      }
      loadedChunksRef.current.push(newChunk.composite);

      if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
          const newClouds = generateClouds(startX, length);
          setClouds(prev => [...prev, ...newClouds]);
      }

      lastChunkDataRef.current = {
          endX: startX + length,
          endY: newChunk.endY,
          globalIndex: newChunk.endGlobalIndex,
          segmentsSinceFuel: newChunk.nextSegmentsSinceFuel
      };

      setChunks(prev => [...prev, newChunk]);
  }, [config, selectedMap.backgroundType]);

  // Apply Config Updates Real-time
  useEffect(() => {
     if (engineRef.current) {
         engineRef.current.gravity.y = config.GRAVITY;
     }
  }, [config.GRAVITY]);

  // Initialize Particles
  useEffect(() => {
      particlesRef.current = Array.from({ length: config.PARTICLE_POOL_SIZE }).map(() => ({
          x: 0, y: 0, vx: 0, vy: 0, life: 0, maxLife: 0, active: false, type: 'dust'
      }));
  }, [config.PARTICLE_POOL_SIZE]);

  // Initialize Game
  useEffect(() => {
    soundManagerRef.current = new SoundManager();
    const engine = createEngine(config);
    engineRef.current = engine;

    const car = createCar(200, -100, selectedCar, config); 
    carRef.current = car;

    const wall = createWall(-1000);
    wallRef.current = wall;

    Matter.World.add(engine.world, [car, wall]);

    lastChunkDataRef.current = { endX: 0, endY: 200, globalIndex: 0, segmentsSinceFuel: 0 }; 
    addChunk(0);
    addChunk(config.CHUNK_SIZE);

    // Collision Events
    Matter.Events.on(engine, 'collisionStart', (event: any) => {
        const pairs = event.pairs;

        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Ground Detection Logic (Wheels)
            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground' || b.label === 'ground'; // Island is also 'ground' labeled for physics but we might check islandBodies

            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                wheelGroundContacts.current += 1;
            }

            // Chassis Collision (Game Over check)
            const isChassisA = bodyA.label === 'chassis';
            const isChassisB = bodyB.label === 'chassis';

            if ((isChassisA && isGround(bodyB)) || (isChassisB && isGround(bodyA))) {
                const chassisBody = isChassisA ? bodyA : bodyB;
                const contacts = pair.activeContacts;
                if (contacts) {
                    for (const contact of contacts) {
                        const vertex = contact.vertex;
                        const localX = vertex.x - chassisBody.position.x;
                        const localY = vertex.y - chassisBody.position.y;

                        const angle = -chassisBody.angle;
                        const sin = Math.sin(angle);
                        const cos = Math.cos(angle);

                        const rotatedX = localX * cos - localY * sin;
                        const rotatedY = localX * sin + localY * cos;

                        if (rotatedY < -10 && Math.abs(rotatedX) < 40) {
                            gameStateRef.current.isGameOver = true;
                            soundManagerRef.current?.updateContinuous(0, true, false);
                            onGameOver(gameStateRef.current.distance, gameStateRef.current.coins);
                            break;
                        }
                    }
                }
            }

            // Collectibles & Hazards Logic
            let itemBody = null;
            const isCarPart = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);

            if (isCarPart(bodyA)) {
                if (['coin', 'fuel', 'water', 'bomb'].includes(bodyB.label)) itemBody = bodyB;
            }
            if (isCarPart(bodyB)) {
                if (['coin', 'fuel', 'water', 'bomb'].includes(bodyA.label)) itemBody = bodyA;
            }

            if (itemBody) {
                // WATER
                if (itemBody.label === 'water') {
                    isInWaterRef.current = true;
                }
                // BOMB
                else if (itemBody.label === 'bomb') {
                    if (!processedBodyIds.current.has(itemBody.id)) {
                        processedBodyIds.current.add(itemBody.id);

                        // EXPLOSION LOGIC - MAJOR BOOST
                        const carBody = carRef.current.bodies[0]; // Chassis

                        // Random horizontal variation
                        const randomX = (Math.random() - 0.5) * 0.2;

                        // SUPER Massive upward impulse to launch car
                        Matter.Body.applyForce(carBody, carBody.position, { x: randomX, y: -4.0 });

                        // Add some spin
                        Matter.Body.setAngularVelocity(carBody, (Math.random() - 0.5) * 0.5);

                        setNotification({ text: "BLAST OFF!", subText: "Gravity Mine", id: Date.now() });
                        setTimeout(() => setNotification(null), 1000);

                        // Explosion particles
                        spawnParticles(itemBody.position.x, itemBody.position.y, 40, 'explosion');

                        // Hide bomb
                        setTriggeredBombIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                        Matter.World.remove(engine.world, itemBody, true);
                    }
                }
                // COIN / FUEL
                else if (!processedBodyIds.current.has(itemBody.id)) {
                    processedBodyIds.current.add(itemBody.id);
                    Matter.World.remove(engine.world, itemBody, true);

                    if (itemBody.label === 'coin') {
                        soundManagerRef.current?.playCoinSound(); 
                        gameStateRef.current.coins += config.COIN_VALUE;
                        if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
                        setCollectedCoinIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    } else if (itemBody.label === 'fuel') {
                        soundManagerRef.current?.playCoinSound(); 
                        fuelRef.current = Math.min(config.MAX_FUEL, fuelRef.current + config.FUEL_CAN_VALUE);
                        setNotification({ text: "FUEL!", subText: `+${Math.round(config.FUEL_CAN_VALUE/config.MAX_FUEL * 100)}%`, id: Date.now() });
                        setTimeout(() => setNotification(null), 1500);
                        setCollectedFuelIds(prev => { const next = new Set(prev); next.add(itemBody.id); return next; });
                    }
                }
            }

            // Particle Logic
            let wheelBody = null;
            if ((isWheelA && isGround(bodyB))) wheelBody = bodyA;
            if ((isWheelB && isGround(bodyA))) wheelBody = bodyB;

            if (wheelBody) {
                const speed = Matter.Vector.magnitude(wheelBody.velocity);
                if (speed > 5) {
                    spawnParticles(wheelBody.position.x, wheelBody.position.y + 15, 3, speed > 10 ? 'spark' : 'dust');
                }
            }
        }
    });

    Matter.Events.on(engine, 'collisionEnd', (event: any) => {
        const pairs = event.pairs;
        for (let i = 0; i < pairs.length; i++) {
            const pair = pairs[i];
            const bodyA = pair.bodyA;
            const bodyB = pair.bodyB;

            // Check Water Exit
            const isCarPart = (b: any) => ['chassis', 'wheelBack', 'wheelFront'].includes(b.label);
            if ((isCarPart(bodyA) && bodyB.label === 'water') || (isCarPart(bodyB) && bodyA.label === 'water')) {
                isInWaterRef.current = false;
            }

            const isWheelA = bodyA.label === 'wheelBack' || bodyA.label === 'wheelFront';
            const isWheelB = bodyB.label === 'wheelBack' || bodyB.label === 'wheelFront';
            const isGround = (b: any) => b.label === 'ground';

            if ((isWheelA && isGround(bodyB)) || (isWheelB && isGround(bodyA))) {
                wheelGroundContacts.current = Math.max(0, wheelGroundContacts.current - 1);
            }
        }
    });

    requestRef.current = requestAnimationFrame(animate);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      Matter.Engine.clear(engine);
      soundManagerRef.current?.updateContinuous(0, true, false);
    };
  }, [addChunk, selectedCar, onGameOver, config.CHUNK_SIZE, config.COIN_VALUE]);

  const spawnParticles = (x: number, y: number, count: number, type: 'dust' | 'spark' | 'explosion') => {
      let spawned = 0;
      for (let i = 0; i < particlesRef.current.length; i++) {
          if (spawned >= count) break;
          const p = particlesRef.current[i];
          if (!p.active) {
              p.active = true;
              p.x = x + (Math.random() * 20 - 10);
              p.y = y + (Math.random() * 20 - 10);
              p.type = type;
              p.maxLife = type === 'explosion' ? 60 : config.PARTICLE_LIFETIME + Math.random() * 20;
              p.life = p.maxLife;

              const speed = type === 'explosion' ? Math.random() * 10 + 5 : Math.random() * 3 + 1;
              const angle = Math.random() * Math.PI * 2;
              p.vx = Math.cos(angle) * speed;
              p.vy = Math.sin(angle) * speed;

              spawned++;
          }
      }
  };

  const interpolateColor = (color1: string, color2: string, factor: number) => {
    const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color1);
    const result2 = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(color2);
    if(result && result2) {
        const r1 = parseInt(result[1], 16), g1 = parseInt(result[2], 16), b1 = parseInt(result[3], 16);
        const r2 = parseInt(result2[1], 16), g2 = parseInt(result2[2], 16), b2 = parseInt(result2[3], 16);
        const r = Math.round(r1 + factor * (r2 - r1));
        const g = Math.round(g1 + factor * (g2 - g1));
        const b = Math.round(b1 + factor * (b2 - b1));
        return `rgb(${r}, ${g}, ${b})`;
    }
    return color1;
  };

  // Ensure Audio Context is resumed on first user interaction
  useEffect(() => {
    const handleInput = () => {
        soundManagerRef.current?.resume();
    };
    window.addEventListener('keydown', handleInput);
    window.addEventListener('mousedown', handleInput);
    window.addEventListener('touchstart', handleInput);
    return () => {
        window.removeEventListener('keydown', handleInput);
        window.removeEventListener('mousedown', handleInput);
        window.removeEventListener('touchstart', handleInput);
    };
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = true;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = true;
    };
    const handleKeyUp = (e: KeyboardEvent) => {
      if (['ArrowRight', 'd'].includes(e.key)) gameStateRef.current.keys.right = false;
      if (['ArrowLeft', 'a'].includes(e.key)) gameStateRef.current.keys.left = false;
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const animate = useCallback(() => {
    const engine = engineRef.current;
    const car = carRef.current;

    if (!engine || !car || gameStateRef.current.isGameOver) return;

    // Update Sound Bar
    if (soundManagerRef.current && soundBarRef.current) {
        const level = soundManagerRef.current.getAudioLevel();
        const height = Math.min(100, level * 300); 
        soundBarRef.current.style.height = `${height}%`;
        soundBarRef.current.style.opacity = height > 2 ? '1' : '0.3';
    }

    const CONFIG = config;

    // Day/Night Cycle Logic (omitted for brevity, same as before)
    if (selectedMap.backgroundType === 'earth' || selectedMap.backgroundType === 'highway') {
         // ... existing day/night logic ...
    } else {
         if (containerRef.current) {
            containerRef.current.style.background = `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})`;
        }
    }

    // --- WATER PHYSICS ---
    if (isInWaterRef.current) {
        // Apply heavy drag
        const chassis = car.bodies[0];
        Matter.Body.setVelocity(chassis, {
            x: chassis.velocity.x * 0.9,
            y: chassis.velocity.y * 0.9 // Also slow falling
        });
        // Slightly floaty
        Matter.Body.applyForce(chassis, chassis.position, { x: 0, y: -0.005 });
    }

    Matter.Engine.update(engine, 1000 / 60);

    // --- CAR PHYSICS LOGIC ---
    const { keys } = gameStateRef.current;
    const chassis = car.bodies.find((b: any) => b.label === 'chassis');
    const wheelBack = car.bodies.find((b: any) => b.label === 'wheelBack');
    const wheelFront = car.bodies.find((b: any) => b.label === 'wheelFront');

    const maxSpeed = selectedCar.speed * (isInWaterRef.current ? 0.5 : 1.0); // Slower in water
    const acceleration = selectedCar.acceleration;

    const isGrounded = wheelGroundContacts.current > 0;

    // --- FUEL LOGIC ---
    if (keys.right) {
        fuelRef.current -= CONFIG.FUEL_CONSUMPTION;
        if (fuelRef.current <= 0) {
            fuelRef.current = 0;
            gameStateRef.current.isGameOver = true;
            soundManagerRef.current?.updateContinuous(0, true, false);
            setNotification({ text: "OUT OF FUEL!", subText: "Game Over", id: Date.now() });
            setTimeout(() => onGameOver(gameStateRef.current.distance, gameStateRef.current.coins), 1000);
        }
    }

    if (hudFuelBarRef.current) {
        const pct = (fuelRef.current / CONFIG.MAX_FUEL) * 100;
        hudFuelBarRef.current.style.width = `${pct}%`;
        if (pct < 20) hudFuelBarRef.current.style.backgroundColor = '#ef4444';
        else hudFuelBarRef.current.style.backgroundColor = '#eab308';
    }

    // --- AUDIO UPDATE ---
    if (soundManagerRef.current && chassis) {
        const speed = Matter.Vector.magnitude(chassis.velocity);
        const speedRatio = Math.min(1.5, speed / 25);
        soundManagerRef.current.updateContinuous(speedRatio, isGrounded, keys.right);
    }

    const rotationSpeed = isGrounded ? CONFIG.GROUND_ROTATION_SPEED : CONFIG.AIR_ROTATION_SPEED;
    const maxRotation = CONFIG.MAX_ROTATION_SPEED;
    const brakeRotationFactor = 0.5;

    // Stunt Logic (same as before) ...
    if (isGrounded) {
       if (stuntRef.current.inAir) {
           if (stuntRef.current.airTime > 60) {
               const seconds = (stuntRef.current.airTime / 60).toFixed(1);
               const airBonus = Math.floor(stuntRef.current.airTime * 50);
               const flips = stuntRef.current.flips;
               let totalBonus = airBonus;
               let text = `AIR TIME ${seconds}s`;
               let subText = `+$${airBonus}`;
               if (flips > 0) {
                   const flipBonus = flips * 1000;
                   totalBonus += flipBonus;
                   text = `${flips > 1 ? 'DOUBLE ' : ''}FLIP!`;
                   subText = `+$${totalBonus} (Air: ${seconds}s)`;
               }
               gameStateRef.current.coins += totalBonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text, subText, id: Date.now() });
               setTimeout(() => setNotification(null), 3000);
           } else if (stuntRef.current.flips > 0) {
               const bonus = stuntRef.current.flips * 1000;
               gameStateRef.current.coins += bonus;
               if (hudCoinsRef.current) hudCoinsRef.current.innerText = `$ ${gameStateRef.current.coins}`;
               setNotification({ text: `${stuntRef.current.flips > 1 ? 'DOUBLE ' : ''}FLIP!`, subText: `+$${bonus}`, id: Date.now() });
               setTimeout(() => setNotification(null), 2500);
           }
           stuntRef.current = { inAir: false, startAngle: 0, flips: 0, airTime: 0 };
       }
    } else {
       if (!stuntRef.current.inAir) {
           stuntRef.current.inAir = true;
           stuntRef.current.startAngle = chassis.angle;
           stuntRef.current.flips = 0;
           stuntRef.current.airTime = 0;
       } else {
           stuntRef.current.airTime++;
           const diff = Math.abs(chassis.angle - stuntRef.current.startAngle);
           const currentFlips = Math.floor(diff / (Math.PI * 1.8));
           if (currentFlips > stuntRef.current.flips) {
               stuntRef.current.flips = currentFlips;
           }
       }
    }

    const applyPower = (targetSpeed: number) => {
        if (selectedCar.driveTrain === 'RWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelBack, targetSpeed);
        }
        if (selectedCar.driveTrain === 'FWD' || selectedCar.driveTrain === 'AWD') {
             Matter.Body.setAngularVelocity(wheelFront, targetSpeed);
        }
    };

    if (keys.right) {
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed < maxSpeed) {
          applyPower(Math.min(currentSpeed + acceleration, maxSpeed));
      }
      if (chassis.angularVelocity > -maxRotation) {
         Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity - rotationSpeed);
      }
    } else if (keys.left) {
      const targetReverse = -maxSpeed * 0.5;
      const currentSpeed = (selectedCar.driveTrain === 'FWD') ? wheelFront.angularVelocity : wheelBack.angularVelocity;
      if (currentSpeed > targetReverse) {
         applyPower(Math.max(currentSpeed - acceleration * 1.5, targetReverse));
      }
      if (chassis.angularVelocity < maxRotation) {
        Matter.Body.setAngularVelocity(chassis, chassis.angularVelocity + (rotationSpeed * brakeRotationFactor));
      }
    }

    // --- RENDER ---
    if (chassisDomRef.current) {
        const cPos = chassis.position;
        const cAngle = chassis.angle * (180 / Math.PI);
        chassisDomRef.current.setAttribute('transform', `translate(${cPos.x}, ${cPos.y}) rotate(${cAngle})`);

        // Wheel updates (same as before)
        const wbPos = wheelBack.position;
        const wbAngle = wheelBack.angle * (180 / Math.PI);
        wheelBackDomRef.current!.setAttribute('cx', wbPos.x);
        wheelBackDomRef.current!.setAttribute('cy', wbPos.y);
        wheelBackSpokesRef.current!.setAttribute('transform', `translate(${wbPos.x}, ${wbPos.y}) rotate(${wbAngle})`);

        const wfPos = wheelFront.position;
        const wfAngle = wheelFront.angle * (180 / Math.PI);
        wheelFrontDomRef.current!.setAttribute('cx', wfPos.x);
        wheelFrontDomRef.current!.setAttribute('cy', wfPos.y);
        wheelFrontSpokesRef.current!.setAttribute('transform', `translate(${wfPos.x}, ${wfPos.y}) rotate(${wfAngle})`);
    }

    // Chunk Loading
    const carX = chassis.position.x;
    if (carX > lastChunkDataRef.current.endX - CONFIG.RENDER_DISTANCE) {
        addChunk(lastChunkDataRef.current.endX);
    }

    // Wall Update
    const wallTargetX = carX - CONFIG.WALL_DISTANCE;
    if (wallRef.current && wallTargetX > wallRef.current.position.x) {
        Matter.Body.setPosition(wallRef.current, { x: wallTargetX, y: chassis.position.y });
    }

    // Particles
    particlesRef.current.forEach((p, i) => {
        const el = particleDomRefs.current[i];
        if (!el) return;

        if (p.active) {
            p.x += p.vx;
            p.y += p.vy;
            p.vy += p.type === 'explosion' ? 0.05 : 0.2; 
            p.life--;

            if (p.life <= 0) {
                p.active = false;
                el.setAttribute('visibility', 'hidden');
            } else {
                el.setAttribute('visibility', 'visible');
                el.setAttribute('cx', p.x.toString());
                el.setAttribute('cy', p.y.toString());
                const color = p.type === 'explosion' ? '#ef4444' : (p.type === 'spark' ? COLORS.particleSpark : selectedMap.particleColor);
                el.setAttribute('fill', color);
                el.setAttribute('opacity', (p.life / p.maxLife).toString());
                el.setAttribute('r', (p.type === 'spark' ? 2 : (p.type === 'explosion' ? 6 : 4)).toString());
            }
        } else {
            el.setAttribute('visibility', 'hidden');
        }
    });

    // Camera
    if (svgRef.current) {
       cameraPosRef.current = { x: carX, y: chassis.position.y };
       const velocity = Matter.Vector.magnitude(chassis.velocity);
       const speedRatio = Math.min(Math.max(0, velocity - 5) / 20, 1.0);
       const targetZoom = 1.0 + speedRatio * (CONFIG.MAX_ZOOM_FACTOR - 1.0);
       cameraZoomRef.current = cameraZoomRef.current + (targetZoom - cameraZoomRef.current) * 0.05;

       const currentZoom = cameraZoomRef.current;
       const viewW = CONFIG.BASE_VIEWPORT_WIDTH * currentZoom;
       const viewH = CONFIG.BASE_VIEWPORT_HEIGHT * currentZoom;

       const viewBoxX = carX - viewW * 0.3; 
       const viewBoxY = chassis.position.y - viewH * 0.6; 

       svgRef.current.setAttribute('viewBox', `${viewBoxX} ${viewBoxY} ${viewW} ${viewH}`);

       if (backgroundLayerRef.current) {
           const parallaxFactor = 0.05; 
           backgroundLayerRef.current.setAttribute('transform', `translate(${carX - viewBoxX - (carX * 0.02)}, ${chassis.position.y - viewBoxY - 200})`);
       }
    }

    // HUD
    const currentDist = Math.max(0, Math.floor((chassis.position.x - 200) / 10)); 
    gameStateRef.current.distance = currentDist;
    if (hudDistanceRef.current) hudDistanceRef.current.innerText = `${currentDist} m`;

    requestRef.current = requestAnimationFrame(animate);
  }, [onGameOver, addChunk, selectedCar, config, selectedMap]);

  // Decoration Rendering (unchanged, just included for context if needed, but we need to add new renderers)
  const decorationsElements = useMemo(() => {
    return chunks.flatMap(chunk => 
        chunk.decorations.map((deco, i) => {
           const angleDeg = deco.angle * (180/Math.PI);
           if (deco.type === 4) {
             return (
               <g key={`fence-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-15" width="4" height="15" fill="#64748b" />
                  <rect x="-20" y="-12" width="45" height="4" fill="#94a3b8" />
                  <rect x="-20" y="-8" width="45" height="1" fill="#cbd5e1" opacity="0.5" />
               </g>
             );
           }
           if (deco.type === 3) {
             return (
               <g key={`lamp-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                  <rect x="-2" y="-80" width="4" height="80" fill={COLORS.lampPost} />
                  <rect x="0" y="-85" width="25" height="5" fill={COLORS.lampPost} />
                  <circle cx="20" cy="-80" r="5" fill={COLORS.lampLight} />
                  <circle cx="20" cy="-80" r="40" fill="url(#lampGlowGradient)" />
               </g>
             )
           }
           if (selectedMap.backgroundType === 'moon') {
               return (
                 <g key={`rock-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg})`}>
                     <circle cx="0" cy="5" r={deco.scale * 5} fill={selectedMap.groundDarkColor} opacity="0.6" />
                 </g>
               )
           }
           if (selectedMap.backgroundType === 'highway' || selectedMap.backgroundType === 'mystical') {
               return null; 
           }
           const d = `M 0 0 Q 5 -15 0 -25 Q -5 -15 0 0 M -3 0 Q -8 -10 -5 -20 M 3 0 Q 8 -10 5 -20`;
           return (
             <g key={`grass-${chunk.id}-${i}`} transform={`translate(${deco.x}, ${deco.y}) rotate(${angleDeg + 90}) scale(${deco.scale})`}>
                <path d={d} stroke={COLORS.grassDetail} strokeWidth="2" fill="none" opacity="0.8" />
             </g>
           );
        })
    );
  }, [chunks, selectedMap]);

  const terrainPaths = useMemo(() => {
      return chunks.map(chunk => {
        const points = chunk.pathData;
        if (points.length === 0) return null;
        let path = `M ${points[0].x} ${points[0].y}`;
        for(let i=1; i<points.length; i++) {
            path += ` L ${points[i].x} ${points[i].y}`;
        }
        path += ` L ${points[points.length-1].x} ${points[points.length-1].y + 800}`;
        path += ` L ${points[0].x} ${points[0].y + 800}`;
        path += " Z"; 
        return (
            <path 
                key={`terrain-${chunk.id}`}
                d={path} 
                fill="url(#groundPattern)" 
                stroke={selectedMap.groundDarkColor} 
                strokeWidth="5" 
                strokeLinejoin="round"
            />
        );
      });
  }, [chunks, selectedMap]);

  // NEW RENDERING FOR HAZARDS
  const hazardElements = useMemo(() => {
      return chunks.flatMap(chunk => {
          const elements = [];

          // WATER
          if (chunk.waterBodies) {
              chunk.waterBodies.forEach(b => {
                 elements.push(
                     <rect 
                        key={`water-${b.id}`} 
                        x={b.position.x - 100} y={b.position.y - 20} 
                        width="200" height="40" 
                        fill={selectedMap.backgroundType === 'mystical' ? 'url(#mysticalWaterGradient)' : COLORS.water} 
                        rx="10"
                        className="animate-pulse"
                     />
                 ) 
              });
          }

          // BOMBS
          if (chunk.bombBodies) {
              chunk.bombBodies.forEach(b => {
                  if (triggeredBombIds.has(b.id)) return;
                  elements.push(
                      <g key={`bomb-${b.id}`} transform={`translate(${b.position.x}, ${b.position.y})`}>
                          <circle r="8" fill={COLORS.bomb} opacity="0.8" />
                          <path d="M -4 0 L 4 0 M 0 -4 L 0 4" stroke="#fff" strokeWidth="2" />
                          <circle r="12" fill="none" stroke={COLORS.bomb} strokeWidth="1" strokeDasharray="2,2" className="animate-spin-slow" />
                      </g>
                  );
              });
          }

          // ISLANDS & RAMPS (Use Ground Texture)
          const groundBodies = [...(chunk.islandBodies || []), ...(chunk.rampBodies || [])];
          if (groundBodies.length > 0) {
              groundBodies.forEach(b => {
                  if (b.vertices && b.vertices.length > 0) {
                      let path = `M ${b.vertices[0].x} ${b.vertices[0].y}`;
                      for (let i = 1; i < b.vertices.length; i++) {
                          path += ` L ${b.vertices[i].x} ${b.vertices[i].y}`;
                      }
                      path += ' Z';

                      elements.push(
                          <g key={`ground-body-${b.id}`}>
                              {/* Main jagged rock using ground pattern */}
                              <path d={path} fill="url(#groundPattern)" stroke={selectedMap.groundColor} strokeWidth="2" />

                              {/* Visual Highlight line on top edge */}
                              <line 
                                x1={b.vertices[0].x} y1={b.vertices[0].y} 
                                x2={b.vertices[1].x} y2={b.vertices[1].y} 
                                stroke={selectedMap.groundColor} 
                                strokeWidth="6" 
                                strokeLinecap="round"
                              />
                          </g>
                      );
                  }
              });
          }

          return elements;
      });
  }, [chunks, triggeredBombIds, selectedMap]);

  const coinElements = useMemo(() => {
      return chunks.flatMap(chunk => 
          chunk.coinBodies.map((coinBody) => {
              if (collectedCoinIds.has(coinBody.id)) return null;
              return (
                  <g key={`coin-${coinBody.id}`} transform={`translate(${coinBody.position.x}, ${coinBody.position.y})`}>
                      <circle r={config.COIN_SIZE} fill={COLORS.coinOuter} />
                      <circle r={config.COIN_SIZE * 0.7} fill={COLORS.coinInner} />
