        />

        <circle ref={wheelBackDomRef} r={config.WHEEL_SIZE} fill={selectedCar.wheelColor} />
        <g ref={wheelBackSpokesRef}>
             <line x1={-config.WHEEL_SIZE} y1="0" x2={config.WHEEL_SIZE} y2="0" stroke={COLORS.carRim} strokeWidth="4" />
